#include "biblia.h"

void Biblia::CarregarMarcos(Biblia* b) {
    b->dados[MARCOS].nome = wxT("Marcos");

    b->dados[MARCOS].capitulos[1].versos[1] = wxT("Princípio do evangelho de Jesus Cristo, Filho de Deus.");
    b->dados[MARCOS].capitulos[1].versos[2] = wxT("Conforme está escrito no profeta Isaías: Eis que envio ante a tua face o meu mensageiro, que há de preparar o teu caminho;");
    b->dados[MARCOS].capitulos[1].versos[3] = wxT("voz do que clama no deserto: Preparai o caminho do Senhor, endireitai as suas veredas;");
    b->dados[MARCOS].capitulos[1].versos[4] = wxT("assim apareceu João, o Batista, no deserto, pregando o batismo de arrependimento para remissão dos pecados.");
    b->dados[MARCOS].capitulos[1].versos[5] = wxT("E saíam a ter com ele toda a terra da Judéia, e todos os moradores de Jerusalém; e eram por ele batizados no rio Jordão, confessando os seus pecados.");
    b->dados[MARCOS].capitulos[1].versos[6] = wxT("Ora, João usava uma veste de pêlos de camelo, e um cinto de couro em torno de seus lombos, e comia gafanhotos e mel silvestre.");
    b->dados[MARCOS].capitulos[1].versos[7] = wxT("E pregava, dizendo: Após mim vem aquele que é mais poderoso do que eu, de quem não sou digno de, inclinando-me, desatar a correia das alparcas.");
    b->dados[MARCOS].capitulos[1].versos[8] = wxT("Eu vos batizei em água; ele, porém, vos batizará no Espírito Santo.");
    b->dados[MARCOS].capitulos[1].versos[9] = wxT("E aconteceu naqueles dias que veio Jesus de Nazaré da Galiléia, e foi batizado por João no Jordão.");
    b->dados[MARCOS].capitulos[1].versos[10] = wxT("E logo, quando saía da água, viu os céus se abrirem, e o Espírito, qual pomba, a descer sobre ele;");
    b->dados[MARCOS].capitulos[1].versos[11] = wxT("e ouviu-se dos céus esta voz: Tu és meu Filho amado; em ti me comprazo.");
    b->dados[MARCOS].capitulos[1].versos[12] = wxT("Imediatamente o Espírito o impeliu para o deserto.");
    b->dados[MARCOS].capitulos[1].versos[13] = wxT("E esteve no deserto quarenta dias sentado tentado por Satanás; estava entre as feras, e os anjos o serviam.");
    b->dados[MARCOS].capitulos[1].versos[14] = wxT("Ora, depois que João foi entregue, veio Jesus para a Galiléia pregando o evangelho de Deus");
    b->dados[MARCOS].capitulos[1].versos[15] = wxT("e dizendo: O tempo está cumprido, e é chegado o reino de Deus. Arrependei-vos, e crede no evangelho.");
    b->dados[MARCOS].capitulos[1].versos[16] = wxT("E, andando junto do mar da Galiléia, viu a Simão, e a André, irmão de Simão, os quais lançavam a rede ao mar, pois eram pescadores.");
    b->dados[MARCOS].capitulos[1].versos[17] = wxT("Disse-lhes Jesus: Vinde após mim, e eu farei que vos torneis pescadores de homens.");
    b->dados[MARCOS].capitulos[1].versos[18] = wxT("Então eles, deixando imediatamente as suas redes, o seguiram.");
    b->dados[MARCOS].capitulos[1].versos[19] = wxT("E ele, passando um pouco adiante, viu Tiago, filho de Zebedeu, e João, seu irmão, que estavam no barco, consertando as redes,");
    b->dados[MARCOS].capitulos[1].versos[20] = wxT("e logo os chamou; eles, deixando seu pai Zebedeu no barco com os empregados, o seguiram.");
    b->dados[MARCOS].capitulos[1].versos[21] = wxT("Entraram em Cafarnaum; e, logo no sábado, indo ele à sinagoga, pôs-se a ensinar.");
    b->dados[MARCOS].capitulos[1].versos[22] = wxT("E maravilhavam-se da sua doutrina, porque os ensinava como tendo autoridade, e não como os escribas.");
    b->dados[MARCOS].capitulos[1].versos[23] = wxT("Ora, estava na sinagoga um homem possesso dum espírito imundo, o qual gritou:");
    b->dados[MARCOS].capitulos[1].versos[24] = wxT("Que temos nós contigo, Jesus, nazareno? Vieste destruir-nos? Bem sei quem és: o Santo de Deus.");
    b->dados[MARCOS].capitulos[1].versos[25] = wxT("Mas Jesus o repreendeu, dizendo: Cala-te, e sai dele.");
    b->dados[MARCOS].capitulos[1].versos[26] = wxT("Então o espírito imundo, convulsionando-o e clamando com grande voz, saiu dele.");
    b->dados[MARCOS].capitulos[1].versos[27] = wxT("E todos se maravilharam a ponto de perguntarem entre si, dizendo: Que é isto? Uma nova doutrina com autoridade! Pois ele ordena aos espíritos imundos, e eles lhe obedecem!");
    b->dados[MARCOS].capitulos[1].versos[28] = wxT("E logo correu a sua fama por toda a região da Galiléia.");
    b->dados[MARCOS].capitulos[1].versos[29] = wxT("Em seguida, saiu da sinagoga e foi a casa de Simão e André com Tiago e João.");
    b->dados[MARCOS].capitulos[1].versos[30] = wxT("A sogra de Simão estava de cama com febre, e logo lhe falaram a respeito dela.");
    b->dados[MARCOS].capitulos[1].versos[31] = wxT("Então Jesus, chegando-se e tomando-a pela mão, a levantou; e a febre a deixou, e ela os servia.");
    b->dados[MARCOS].capitulos[1].versos[32] = wxT("Sendo já tarde, tendo-se posto o sol, traziam-lhe todos os enfermos, e os endemoninhados;");
    b->dados[MARCOS].capitulos[1].versos[33] = wxT("e toda a cidade estava reunida à porta;");
    b->dados[MARCOS].capitulos[1].versos[34] = wxT("e ele curou muitos doentes atacados de diversas moléstias, e expulsou muitos demônios; mas não permitia que os demônios falassem, porque o conheciam.");
    b->dados[MARCOS].capitulos[1].versos[35] = wxT("De madrugada, ainda bem escuro, levantou-se, saiu e foi a um lugar deserto, e ali orava.");
    b->dados[MARCOS].capitulos[1].versos[36] = wxT("Foram, pois, Simão e seus companheiros procurá-lo;");
    b->dados[MARCOS].capitulos[1].versos[37] = wxT("quando o encontraram, disseram-lhe: Todos te buscam.");
    b->dados[MARCOS].capitulos[1].versos[38] = wxT("Respondeu-lhes Jesus: Vamos a outras partes, às povoações vizinhas, para que eu pregue ali também; pois para isso é que vim.");
    b->dados[MARCOS].capitulos[1].versos[39] = wxT("Foi, então, por toda a Galiléia, pregando nas sinagogas deles e expulsando os demônios.");
    b->dados[MARCOS].capitulos[1].versos[40] = wxT("E veio a ele um leproso que, de joelhos, lhe rogava, dizendo: Se quiseres, bem podes tornar-me limpo.");
    b->dados[MARCOS].capitulos[1].versos[41] = wxT("Jesus, pois, compadecido dele, estendendo a mão, tocou-o e disse-lhe: Quero; sê limpo.");
    b->dados[MARCOS].capitulos[1].versos[42] = wxT("Imediatamente desapareceu dele a lepra e ficou limpo.");
    b->dados[MARCOS].capitulos[1].versos[43] = wxT("E Jesus, advertindo-o secretamente, logo o despediu,");
    b->dados[MARCOS].capitulos[1].versos[44] = wxT("dizendo-lhe: Olha, não digas nada a ninguém; mas vai, mostra-te ao sacerdote e oferece pela tua purificação o que Moisés determinou, para lhes servir de testemunho.");
    b->dados[MARCOS].capitulos[1].versos[45] = wxT("Ele, porém, saindo dali, começou a publicar o caso por toda parte e a divulgá-lo, de modo que Jesus já não podia entrar abertamente numa cidade, mas conservava-se fora em lugares desertos; e de todos os lados iam ter com ele.");

    b->dados[MARCOS].capitulos[2].versos[1] = wxT("Alguns dias depois entrou Jesus outra vez em Cafarnaum, e soube-se que ele estava em casa.");
    b->dados[MARCOS].capitulos[2].versos[2] = wxT("Ajuntaram-se, pois, muitos, a ponta de não caberem nem mesmo diante da porta; e ele lhes anunciava a palavra.");
    b->dados[MARCOS].capitulos[2].versos[3] = wxT("Nisso vieram alguns a trazer-lhe um paralítico, carregado por quatro;");
    b->dados[MARCOS].capitulos[2].versos[4] = wxT("e não podendo aproximar-se dele, por causa da multidão, descobriram o telhado onde estava e, fazendo uma abertura, baixaram o leito em que jazia o paralítico.");
    b->dados[MARCOS].capitulos[2].versos[5] = wxT("E Jesus, vendo-lhes a fé, disse ao paralítico: Filho, perdoados são os teus pecados.");
    b->dados[MARCOS].capitulos[2].versos[6] = wxT("Ora, estavam ali sentados alguns dos escribas, que arrazoavam em seus corações, dizendo:");
    b->dados[MARCOS].capitulos[2].versos[7] = wxT("Por que fala assim este homem? Ele blasfema. Quem pode perdoar pecados senão um só, que é Deus?");
    b->dados[MARCOS].capitulos[2].versos[8] = wxT("Mas Jesus logo percebeu em seu espírito que eles assim arrazoavam dentro de si, e perguntou-lhes: Por que arrazoais desse modo em vossos corações?");
    b->dados[MARCOS].capitulos[2].versos[9] = wxT("Qual é mais fácil? dizer ao paralítico: Perdoados são os teus pecados; ou dizer: Levanta-te, toma o teu leito, e anda?");
    b->dados[MARCOS].capitulos[2].versos[10] = wxT("Ora, para que saibais que o Filho do homem tem sobre a terra autoridade para perdoar pecados { disse ao paralítico },");
    b->dados[MARCOS].capitulos[2].versos[11] = wxT("a ti te digo, levanta-te, toma o teu leito, e vai para tua casa.");
    b->dados[MARCOS].capitulos[2].versos[12] = wxT("Então ele se levantou e, tomando logo o leito, saiu à vista de todos; de modo que todos pasmavam e glorificavam a Deus, dizendo: Nunca vimos coisa semelhante.");
    b->dados[MARCOS].capitulos[2].versos[13] = wxT("Outra vez saiu Jesus para a beira do mar; e toda a multidão ia ter com ele, e ele os ensinava.");
    b->dados[MARCOS].capitulos[2].versos[14] = wxT("Quando ia passando, viu a Levi, filho de Alfeu, sentado na coletoria, e disse-lhe: Segue-me. E ele, levantando-se, o seguiu.");
    b->dados[MARCOS].capitulos[2].versos[15] = wxT("Ora, estando Jesus à mesa em casa de Levi, estavam também ali reclinados com ele e seus discípulos muitos publicanos e pecadores; pois eram em grande número e o seguiam.");
    b->dados[MARCOS].capitulos[2].versos[16] = wxT("Vendo os escribas dos fariseus que comia com os publicanos e pecadores, perguntavam aos discípulos: Por que é que ele como com os publicanos e pecadores?");
    b->dados[MARCOS].capitulos[2].versos[17] = wxT("Jesus, porém, ouvindo isso, disse-lhes: Não necessitam de médico os sãos, mas sim os enfermos; eu não vim chamar justos, mas pecadores.");
    b->dados[MARCOS].capitulos[2].versos[18] = wxT("Ora, os discípulos de João e os fariseus estavam jejuando; e foram perguntar-lhe: Por que jejuam os discípulos de João e os dos fariseus, mas os teus discípulos não jejuam?");
    b->dados[MARCOS].capitulos[2].versos[19] = wxT("Respondeu-lhes Jesus: Podem, porventura, jejuar os convidados às núpcias, enquanto está com eles o noivo? Enquanto têm consigo o noivo não podem jejuar;");
    b->dados[MARCOS].capitulos[2].versos[20] = wxT("dias virão, porém, em que lhes será tirado o noivo; nesses dias, sim hão de jejuar.");
    b->dados[MARCOS].capitulos[2].versos[21] = wxT("Ninguém cose remendo de pano novo em vestido velho; do contrário o remendo novo tira parte do velho, e torna-se maior a rotura.");
    b->dados[MARCOS].capitulos[2].versos[22] = wxT("E ninguém deita vinho novo em odres velhos; do contrário, o vinho novo romperá os odres, e perder-se-á o vinho e também os odres; mas deita-se vinho novo em odres novos.");
    b->dados[MARCOS].capitulos[2].versos[23] = wxT("E sucedeu passar ele num dia de sábado pelas searas; e os seus discípulos, caminhando, começaram a colher espigas.");
    b->dados[MARCOS].capitulos[2].versos[24] = wxT("E os fariseus lhe perguntaram: Olha, por que estão fazendo no sábado o que não é lícito?");
    b->dados[MARCOS].capitulos[2].versos[25] = wxT("Respondeu-lhes ele: Acaso nunca lestes o que fez Davi quando se viu em necessidade e teve fome, ele e seus companheiros?");
    b->dados[MARCOS].capitulos[2].versos[26] = wxT("Como entrou na casa de Deus, no tempo do sumo sacerdote Abiatar, e comeu dos pães da proposição, dos quais não era lícito comer senão aos sacerdotes, e deu também aos companheiros?");
    b->dados[MARCOS].capitulos[2].versos[27] = wxT("E prosseguiu: O sábado foi feito por causa do homem, e não o homem por causa do sábado.");
    b->dados[MARCOS].capitulos[2].versos[28] = wxT("Pelo que o Filho do homem até do sábado é Senhor.");

    b->dados[MARCOS].capitulos[3].versos[1] = wxT("Outra vez entrou numa sinagoga, e estava ali um homem que tinha uma das mãos atrofiada.");
    b->dados[MARCOS].capitulos[3].versos[2] = wxT("E observavam-no para ver se no sábado curaria o homem, a fim de o acusarem.");
    b->dados[MARCOS].capitulos[3].versos[3] = wxT("E disse Jesus ao homem que tinha a mão atrofiada: Levanta-te e vem para o meio.");
    b->dados[MARCOS].capitulos[3].versos[4] = wxT("Então lhes perguntou: É lícito no sábado fazer bem, ou fazer mal? salvar a vida ou matar? Eles, porém, se calaram.");
    b->dados[MARCOS].capitulos[3].versos[5] = wxT("E olhando em redor para eles com indignação, condoendo-se da dureza dos seus corações, disse ao homem: Estende a tua mão. Ele estendeu, e lhe foi restabelecida.");
    b->dados[MARCOS].capitulos[3].versos[6] = wxT("E os fariseus, saindo dali, entraram logo em conselho com os herodianos contra ele, para o matarem.");
    b->dados[MARCOS].capitulos[3].versos[7] = wxT("Jesus, porém, se retirou com os seus discípulos para a beira do mar; e uma grande multidão dos da Galiléia o seguiu; também da Judéia,");
    b->dados[MARCOS].capitulos[3].versos[8] = wxT("e de Jerusalém, da Iduméia e de além do Jordão, e das regiões de Tiro e de Sidom, grandes multidões, ouvindo falar de tudo quanto fazia, vieram ter com ele.");
    b->dados[MARCOS].capitulos[3].versos[9] = wxT("Recomendou, pois, a seus discípulos que se lhe preparasse um barquinho, por causa da multidão, para que não o apertasse;");
    b->dados[MARCOS].capitulos[3].versos[10] = wxT("porque tinha curado a muitos, de modo que todos quantos tinham algum mal arrojavam-se a ele para lhe tocarem.");
    b->dados[MARCOS].capitulos[3].versos[11] = wxT("E os espíritos imundos, quando o viam, prostravam-se diante dele e clamavam, dizendo: Tu és o Filho de Deus.");
    b->dados[MARCOS].capitulos[3].versos[12] = wxT("E ele lhes advertia com insistência que não o dessem a conhecer.");
    b->dados[MARCOS].capitulos[3].versos[13] = wxT("Depois subiu ao monte, e chamou a si os que ele mesmo queria; e vieram a ele.");
    b->dados[MARCOS].capitulos[3].versos[14] = wxT("Então designou doze para que estivessem com ele, e os mandasse a pregar;");
    b->dados[MARCOS].capitulos[3].versos[15] = wxT("e para que tivessem autoridade de expulsar os demônios.");
    b->dados[MARCOS].capitulos[3].versos[16] = wxT("Designou, pois, os doze, a saber: Simão, a quem pôs o nome de Pedro;");
    b->dados[MARCOS].capitulos[3].versos[17] = wxT("Tiago, filho de Zebedeu, e João, irmão de Tiago, aos quais pôs o nome de Boanerges, que significa: Filhos do trovão;");
    b->dados[MARCOS].capitulos[3].versos[18] = wxT("André, Filipe, Bartolomeu, Mateus, Tomé, Tiago, filho de Alfeu, Tadeu, Simão, o cananeu,");
    b->dados[MARCOS].capitulos[3].versos[19] = wxT("e Judas Iscariotes, aquele que o traiu.");
    b->dados[MARCOS].capitulos[3].versos[20] = wxT("Depois entrou numa casa. E afluiu outra vez a multidão, de tal modo que nem podiam comer.");
    b->dados[MARCOS].capitulos[3].versos[21] = wxT("Quando os seus ouviram isso, saíram para o prender; porque diziam: Ele está fora de si.");
    b->dados[MARCOS].capitulos[3].versos[22] = wxT("E os escribas que tinham descido de Jerusalém diziam: Ele está possesso de Belzebu; e: É pelo príncipe dos demônios que expulsa os demônios.");
    b->dados[MARCOS].capitulos[3].versos[23] = wxT("Então Jesus os chamou e lhes disse por parábolas: Como pode Satanás expulsar Satanás?");
    b->dados[MARCOS].capitulos[3].versos[24] = wxT("Pois, se um reino se dividir contra si mesmo, tal reino não pode subsistir;");
    b->dados[MARCOS].capitulos[3].versos[25] = wxT("ou, se uma casa se dividir contra si mesma, tal casa não poderá subsistir;");
    b->dados[MARCOS].capitulos[3].versos[26] = wxT("e se Satanás se tem levantado contra si mesmo, e está dividido, tampouco pode ele subsistir; antes tem fim.");
    b->dados[MARCOS].capitulos[3].versos[27] = wxT("Pois ninguém pode entrar na casa do valente e roubar-lhe os bens, se primeiro não amarrar o valente; e então lhe saqueará a casa.");
    b->dados[MARCOS].capitulos[3].versos[28] = wxT("Em verdade vos digo: Todos os pecados serão perdoados aos filhos dos homens, bem como todas as blasfêmias que proferirem;");
    b->dados[MARCOS].capitulos[3].versos[29] = wxT("mas aquele que blasfemar contra o Espírito Santo, nunca mais terá perdão, mas será réu de pecado eterno.");
    b->dados[MARCOS].capitulos[3].versos[30] = wxT("Porquanto eles diziam: Está possesso de um espírito imundo.");
    b->dados[MARCOS].capitulos[3].versos[31] = wxT("Chegaram então sua mãe e seus irmãos e, ficando da parte de fora, mandaram chamá-lo.");
    b->dados[MARCOS].capitulos[3].versos[32] = wxT("E a multidão estava sentada ao redor dele, e disseram-lhe: Eis que tua mãe e teus irmãos estão lá fora e te procuram.");
    b->dados[MARCOS].capitulos[3].versos[33] = wxT("Respondeu-lhes Jesus, dizendo: Quem é minha mãe e meus irmãos!");
    b->dados[MARCOS].capitulos[3].versos[34] = wxT("E olhando em redor para os que estavam sentados à roda de si, disse: Eis aqui minha mãe e meus irmãos!");
    b->dados[MARCOS].capitulos[3].versos[35] = wxT("Pois aquele que fizer a vontade de Deus, esse é meu irmão, irmã e mãe.");

    b->dados[MARCOS].capitulos[4].versos[1] = wxT("Outra vez começou a ensinar à beira do mar. E reuniu-se a ele tão grande multidão que ele entrou num barco e sentou-se nele, sobre o mar; e todo o povo estava em terra junto do mar.");
    b->dados[MARCOS].capitulos[4].versos[2] = wxT("Então lhes ensinava muitas coisas por parábolas, e lhes dizia no seu ensino:");
    b->dados[MARCOS].capitulos[4].versos[3] = wxT("Ouvi: Eis que o semeador saiu a semear;");
    b->dados[MARCOS].capitulos[4].versos[4] = wxT("e aconteceu que, quando semeava, uma parte da semente caiu à beira do caminho, e vieram as aves e a comeram.");
    b->dados[MARCOS].capitulos[4].versos[5] = wxT("Outra caiu no solo pedregoso, onde não havia muita terra: e logo nasceu, porque não tinha terra profunda;");
    b->dados[MARCOS].capitulos[4].versos[6] = wxT("mas, saindo o sol, queimou-se; e, porque não tinha raiz, secou-se.");
    b->dados[MARCOS].capitulos[4].versos[7] = wxT("E outra caiu entre espinhos; e cresceram os espinhos, e a sufocaram; e não deu fruto.");
    b->dados[MARCOS].capitulos[4].versos[8] = wxT("Mas outras caíram em boa terra e, vingando e crescendo, davam fruto; e um grão produzia trinta, outro sessenta, e outro cem.");
    b->dados[MARCOS].capitulos[4].versos[9] = wxT("E disse-lhes: Quem tem ouvidos para ouvir, ouça.");
    b->dados[MARCOS].capitulos[4].versos[10] = wxT("Quando se achou só, os que estavam ao redor dele, com os doze, interrogaram-no acerca da parábola.");
    b->dados[MARCOS].capitulos[4].versos[11] = wxT("E ele lhes disse: A vós é confiado o mistério do reino de Deus, mas aos de fora tudo se lhes diz por parábolas;");
    b->dados[MARCOS].capitulos[4].versos[12] = wxT("para que vendo, vejam, e não percebam; e ouvindo, ouçam, e não entendam; para que não se convertam e sejam perdoados.");
    b->dados[MARCOS].capitulos[4].versos[13] = wxT("Disse-lhes ainda: Não percebeis esta parábola? como pois entendereis todas as parábolas?");
    b->dados[MARCOS].capitulos[4].versos[14] = wxT("O semeador semeia a palavra.");
    b->dados[MARCOS].capitulos[4].versos[15] = wxT("E os que estão junto do caminho são aqueles em quem a palavra é semeada; mas, tendo-a eles ouvido, vem logo Satanás e tira a palavra que neles foi semeada.");
    b->dados[MARCOS].capitulos[4].versos[16] = wxT("Do mesmo modo, aqueles que foram semeados nos lugares pedregosos são os que, ouvindo a palavra, imediatamente com alegria a recebem;");
    b->dados[MARCOS].capitulos[4].versos[17] = wxT("mas não têm raiz em si mesmos, antes são de pouca duração; depois, sobrevindo tribulação ou perseguição por causa da palavra, logo se escandalizam.");
    b->dados[MARCOS].capitulos[4].versos[18] = wxT("Outros ainda são aqueles que foram semeados entre os espinhos; estes são os que ouvem a palavra;");
    b->dados[MARCOS].capitulos[4].versos[19] = wxT("mas os cuidados do mundo, a sedução das riquezas e a cobiça doutras coisas, entrando, sufocam a palavra, e ela fica infrutífera.");
    b->dados[MARCOS].capitulos[4].versos[20] = wxT("Aqueles outros que foram semeados em boa terra são os que ouvem a palavra e a recebem, e dão fruto, a trinta, a sessenta, e a cem, por um.");
    b->dados[MARCOS].capitulos[4].versos[21] = wxT("Disse-lhes mais: Vem porventura a candeia para se meter debaixo do alqueire, ou debaixo da cama? não é antes para se colocar no velador?");
    b->dados[MARCOS].capitulos[4].versos[22] = wxT("Porque nada está encoberto senão para ser manifesto; e nada foi escondido senão para vir à luz.");
    b->dados[MARCOS].capitulos[4].versos[23] = wxT("Se alguém tem ouvidos para ouvir, ouça.");
    b->dados[MARCOS].capitulos[4].versos[24] = wxT("Também lhes disse: Atendei ao que ouvis. Com a medida com que medis vos medirão a vós, e ainda se vos acrescentará.");
    b->dados[MARCOS].capitulos[4].versos[25] = wxT("Pois ao que tem, ser-lhe-á dado; e ao que não tem, até aquilo que tem ser-lhe-á tirado.");
    b->dados[MARCOS].capitulos[4].versos[26] = wxT("Disse também: O reino de Deus é assim como se um homem lançasse semente à terra,");
    b->dados[MARCOS].capitulos[4].versos[27] = wxT("e dormisse e se levantasse de noite e de dia, e a semente brotasse e crescesse, sem ele saber como.");
    b->dados[MARCOS].capitulos[4].versos[28] = wxT("A terra por si mesma produz fruto, primeiro a erva, depois a espiga, e por último o grão cheio na espiga.");
    b->dados[MARCOS].capitulos[4].versos[29] = wxT("Mas assim que o fruto amadurecer, logo lhe mete a foice, porque é chegada a ceifa.");
    b->dados[MARCOS].capitulos[4].versos[30] = wxT("Disse ainda: A que assemelharemos o reino de Deus? ou com que parábola o representaremos?");
    b->dados[MARCOS].capitulos[4].versos[31] = wxT("É como um grão de mostarda que, quando se semeia, é a menor de todas as sementes que há na terra;");
    b->dados[MARCOS].capitulos[4].versos[32] = wxT("mas, tendo sido semeado, cresce e faz-se a maior de todas as hortaliças e cria grandes ramos, de tal modo que as aves do céu podem aninhar-se à sua sombra.");
    b->dados[MARCOS].capitulos[4].versos[33] = wxT("E com muitas parábolas tais lhes dirigia a palavra, conforme podiam compreender.");
    b->dados[MARCOS].capitulos[4].versos[34] = wxT("E sem parábola não lhes falava; mas em particular explicava tudo a seus discípulos.");
    b->dados[MARCOS].capitulos[4].versos[35] = wxT("Naquele dia, quando já era tarde, disse-lhes: Passemos para o outro lado.");
    b->dados[MARCOS].capitulos[4].versos[36] = wxT("E eles, deixando a multidão, o levaram consigo, assim como estava, no barco; e havia com ele também outros barcos.");
    b->dados[MARCOS].capitulos[4].versos[37] = wxT("E se levantou grande tempestade de vento, e as ondas batiam dentro do barco, de modo que já se enchia.");
    b->dados[MARCOS].capitulos[4].versos[38] = wxT("Ele, porém, estava na popa dormindo sobre a almofada; e despertaram-no, e lhe perguntaram: Mestre, não se te dá que pereçamos?");
    b->dados[MARCOS].capitulos[4].versos[39] = wxT("E ele, levantando-se, repreendeu o vento, e disse ao mar: Cala-te, aquieta-te. E cessou o vento, e fez-se grande bonança.");
    b->dados[MARCOS].capitulos[4].versos[40] = wxT("Então lhes perguntou: Por que sois assim tímidos? Ainda não tendes fé?");
    b->dados[MARCOS].capitulos[4].versos[41] = wxT("Encheram-se de grande temor, e diziam uns aos outros: Quem, porventura, é este, que até o vento e o mar lhe obedecem?");

    b->dados[MARCOS].capitulos[5].versos[1] = wxT("Chegaram então ao outro lado do mar, à terra dos gerasenos.");
    b->dados[MARCOS].capitulos[5].versos[2] = wxT("E, logo que Jesus saíra do barco, lhe veio ao encontro, dos sepulcros, um homem com espírito imundo,");
    b->dados[MARCOS].capitulos[5].versos[3] = wxT("o qual tinha a sua morada nos sepulcros; e nem ainda com cadeias podia alguém prendê-lo;");
    b->dados[MARCOS].capitulos[5].versos[4] = wxT("porque, tendo sido muitas vezes preso com grilhões e cadeias, as cadeias foram por ele feitas em pedaços, e os grilhões em migalhas; e ninguém o podia domar;");
    b->dados[MARCOS].capitulos[5].versos[5] = wxT("e sempre, de dia e de noite, andava pelos sepulcros e pelos montes, gritando, e ferindo-se com pedras,");
    b->dados[MARCOS].capitulos[5].versos[6] = wxT("Vendo, pois, de longe a Jesus, correu e adorou-o;");
    b->dados[MARCOS].capitulos[5].versos[7] = wxT("e, clamando com grande voz, disse: Que tenho eu contigo, Jesus, Filho do Deus Altíssimo? conjuro-te por Deus que não me atormentes.");
    b->dados[MARCOS].capitulos[5].versos[8] = wxT("Pois Jesus lhe dizia: Sai desse homem, espírito imundo.");
    b->dados[MARCOS].capitulos[5].versos[9] = wxT("E perguntou-lhe: Qual é o teu nome? Respondeu-lhe ele: Legião é o meu nome, porque somos muitos.");
    b->dados[MARCOS].capitulos[5].versos[10] = wxT("E rogava-lhe muito que não os enviasse para fora da região.");
    b->dados[MARCOS].capitulos[5].versos[11] = wxT("Ora, andava ali pastando no monte uma grande manada de porcos.");
    b->dados[MARCOS].capitulos[5].versos[12] = wxT("Rogaram-lhe, pois, os demônios, dizendo: Manda-nos para aqueles porcos, para que entremos neles.");
    b->dados[MARCOS].capitulos[5].versos[13] = wxT("E ele lho permitiu. Saindo, então, os espíritos imundos, entraram nos porcos; e precipitou-se a manada, que era de uns dois mil, pelo despenhadeiro no mar, onde todos se afogaram.");
    b->dados[MARCOS].capitulos[5].versos[14] = wxT("Nisso fugiram aqueles que os apascentavam, e o anunciaram na cidade e nos campos; e muitos foram ver o que era aquilo que tinha acontecido.");
    b->dados[MARCOS].capitulos[5].versos[15] = wxT("Chegando-se a Jesus, viram o endemoninhado, o que tivera a legião, sentado, vestido, e em perfeito juízo; e temeram.");
    b->dados[MARCOS].capitulos[5].versos[16] = wxT("E os que tinham visto aquilo contaram-lhes como havia acontecido ao endemoninhado, e acerca dos porcos.");
    b->dados[MARCOS].capitulos[5].versos[17] = wxT("Então começaram a rogar-lhe que se retirasse dos seus termos.");
    b->dados[MARCOS].capitulos[5].versos[18] = wxT("E, entrando ele no barco, rogava-lhe o que fora endemoninhado que o deixasse estar com ele.");
    b->dados[MARCOS].capitulos[5].versos[19] = wxT("Jesus, porém, não lho permitiu, mas disse-lhe: Vai para tua casa, para os teus, e anuncia-lhes o quanto o Senhor te fez, e como teve misericórdia de ti.");
    b->dados[MARCOS].capitulos[5].versos[20] = wxT("Ele se retirou, pois, e começou a publicar em Decápolis tudo quanto lhe fizera Jesus; e todos se admiravam.");
    b->dados[MARCOS].capitulos[5].versos[21] = wxT("Tendo Jesus passado de novo no barco para o outro lado, ajuntou-se a ele uma grande multidão; e ele estava à beira do mar.");
    b->dados[MARCOS].capitulos[5].versos[22] = wxT("Chegou um dos chefes da sinagoga, chamado Jairo e, logo que viu a Jesus, lançou-se-lhe aos pés.");
    b->dados[MARCOS].capitulos[5].versos[23] = wxT("e lhe rogava com instância, dizendo: Minha filhinha está nas últimas; rogo-te que venhas e lhe imponhas as mãos para que sare e viva.");
    b->dados[MARCOS].capitulos[5].versos[24] = wxT("Jesus foi com ele, e seguia-o uma grande multidão, que o apertava.");
    b->dados[MARCOS].capitulos[5].versos[25] = wxT("Ora, certa mulher, que havia doze anos padecia de uma hemorragia,");
    b->dados[MARCOS].capitulos[5].versos[26] = wxT("e que tinha sofrido bastante às mãos de muitos médicos, e despendido tudo quanto possuía sem nada aproveitar, antes indo a pior,");
    b->dados[MARCOS].capitulos[5].versos[27] = wxT("tendo ouvido falar a respeito de Jesus, veio por detrás, entre a multidão, e tocou-lhe o manto;");
    b->dados[MARCOS].capitulos[5].versos[28] = wxT("porque dizia: Se tão-somente tocar-lhe as vestes, ficaria curada.");
    b->dados[MARCOS].capitulos[5].versos[29] = wxT("E imediatamente cessou a sua hemorragia; e sentiu no corpo estar já curada do seu mal.");
    b->dados[MARCOS].capitulos[5].versos[30] = wxT("E logo Jesus, percebendo em si mesmo que saíra dele poder, virou-se no meio da multidão e perguntou: Quem me tocou as vestes?");
    b->dados[MARCOS].capitulos[5].versos[31] = wxT("Responderam-lhe os seus discípulos: Vês que a multidão te aperta, e perguntas: Quem me tocou?");
    b->dados[MARCOS].capitulos[5].versos[32] = wxT("Mas ele olhava em redor para ver a que isto fizera.");
    b->dados[MARCOS].capitulos[5].versos[33] = wxT("Então a mulher, atemorizada e trêmula, cônscia do que nela se havia operado, veio e prostrou-se diante dele, e declarou-lhe toda a verdade.");
    b->dados[MARCOS].capitulos[5].versos[34] = wxT("Disse-lhe ele: Filha, a tua fé te salvou; vai-te em paz, e fica livre desse teu mal.");
    b->dados[MARCOS].capitulos[5].versos[35] = wxT("Enquanto ele ainda falava, chegaram pessoas da casa do chefe da sinagoga, a quem disseram: A tua filha já morreu; por que ainda incomodas o Mestre?");
    b->dados[MARCOS].capitulos[5].versos[36] = wxT("O que percebendo Jesus, disse ao chefe da sinagoga: Não temas, crê somente.");
    b->dados[MARCOS].capitulos[5].versos[37] = wxT("E não permitiu que ninguém o acompanhasse, senão Pedro, Tiago, e João, irmão de Tiago.");
    b->dados[MARCOS].capitulos[5].versos[38] = wxT("Quando chegaram a casa do chefe da sinagoga, viu Jesus um alvoroço, e os que choravam e faziam grande pranto.");
    b->dados[MARCOS].capitulos[5].versos[39] = wxT("E, entrando, disse-lhes: Por que fazeis alvoroço e chorais? a menina não morreu, mas dorme.");
    b->dados[MARCOS].capitulos[5].versos[40] = wxT("E riam-se dele; porém ele, tendo feito sair a todos, tomou consigo o pai e a mãe da menina, e os que com ele vieram, e entrou onde a menina estava.");
    b->dados[MARCOS].capitulos[5].versos[41] = wxT("E, tomando a mão da menina, disse-lhe: Talita cumi, que, traduzido, é: Menina, a ti te digo, levanta-te.");
    b->dados[MARCOS].capitulos[5].versos[42] = wxT("Imediatamente a menina se levantou, e pôs-se a andar, pois tinha doze anos. E logo foram tomados de grande espanto.");
    b->dados[MARCOS].capitulos[5].versos[43] = wxT("Então ordenou-lhes expressamente que ninguém o soubesse; e mandou que lhe dessem de comer.");

    b->dados[MARCOS].capitulos[6].versos[1] = wxT("Saiu Jesus dali, e foi para a sua terra, e os seus discípulos o seguiam.");
    b->dados[MARCOS].capitulos[6].versos[2] = wxT("Ora, chegando o sábado, começou a ensinar na sinagoga; e muitos, ao ouvi-lo, se maravilhavam, dizendo: Donde lhe vêm estas coisas? e que sabedoria é esta que lhe é dada? e como se fazem tais milagres por suas mãos?");
    b->dados[MARCOS].capitulos[6].versos[3] = wxT("Não é este o carpinteiro, filho de Maria, irmão de Tiago, de José, de Judas e de Simão? e não estão aqui entre nós suas irmãs? E escandalizavam-se dele.");
    b->dados[MARCOS].capitulos[6].versos[4] = wxT("Então Jesus lhes dizia: Um profeta não fica sem honra senão na sua terra, entre os seus parentes, e na sua própria casa.");
    b->dados[MARCOS].capitulos[6].versos[5] = wxT("E não podia fazer ali nenhum milagre, a não ser curar alguns poucos enfermos, impondo-lhes as mãos.");
    b->dados[MARCOS].capitulos[6].versos[6] = wxT("E admirou-se da incredulidade deles. Em seguida percorria as aldeias circunvizinhas, ensinando.");
    b->dados[MARCOS].capitulos[6].versos[7] = wxT("E chamou a si os doze, e começou a enviá-los a dois e dois, e dava-lhes poder sobre os espíritos imundos;");
    b->dados[MARCOS].capitulos[6].versos[8] = wxT("ordenou-lhes que nada levassem para o caminho, senão apenas um bordão; nem pão, nem alforje, nem dinheiro no cinto;");
    b->dados[MARCOS].capitulos[6].versos[9] = wxT("mas que fossem calçados de sandálias, e que não vestissem duas túnicas.");
    b->dados[MARCOS].capitulos[6].versos[10] = wxT("Dizia-lhes mais: Onde quer que entrardes numa casa, ficai nela até sairdes daquele lugar.");
    b->dados[MARCOS].capitulos[6].versos[11] = wxT("E se qualquer lugar não vos receber, nem os homens vos ouvirem, saindo dali, sacudi o pó que estiver debaixo dos vossos pés, em testemunho conta eles.");
    b->dados[MARCOS].capitulos[6].versos[12] = wxT("Então saíram e pregaram que todos se arrependessem;");
    b->dados[MARCOS].capitulos[6].versos[13] = wxT("e expulsavam muitos demônios, e ungiam muitos enfermos com óleo, e os curavam.");
    b->dados[MARCOS].capitulos[6].versos[14] = wxT("E soube disso o rei Herodes {porque o nome de Jesus se tornara célebre}, e disse: João, o Batista, ressuscitou dos mortos; e por isso estes poderes milagrosos operam nele.");
    b->dados[MARCOS].capitulos[6].versos[15] = wxT("Mas outros diziam: É Elias. E ainda outros diziam: É profeta como um dos profetas.");
    b->dados[MARCOS].capitulos[6].versos[16] = wxT("Herodes, porém, ouvindo isso, dizia: É João, aquele a quem eu mandei degolar: ele ressuscitou.");
    b->dados[MARCOS].capitulos[6].versos[17] = wxT("Porquanto o próprio Herodes mandara prender a João, e encerrá-lo maniatado no cárcere, por causa de Herodias, mulher de seu irmão Filipe; porque ele se havia casado com ela.");
    b->dados[MARCOS].capitulos[6].versos[18] = wxT("Pois João dizia a Herodes: Não te é lícito ter a mulher de teu irmão.");
    b->dados[MARCOS].capitulos[6].versos[19] = wxT("Por isso Herodias lhe guardava rancor e queria matá-lo, mas não podia;");
    b->dados[MARCOS].capitulos[6].versos[20] = wxT("porque Herodes temia a João, sabendo que era varão justo e santo, e o guardava em segurança; e, ao ouvi-lo, ficava muito perplexo, contudo de boa mente o escutava.");
    b->dados[MARCOS].capitulos[6].versos[21] = wxT("Chegado, porém, um dia oportuno quando Herodes no seu aniversário natalício ofereceu um banquete aos grandes da sua corte, aos principais da Galiléia,");
    b->dados[MARCOS].capitulos[6].versos[22] = wxT("entrou a filha da mesma Herodias e, dançando, agradou a Herodes e aos convivas. Então o rei disse à jovem: Pede-me o que quiseres, e eu to darei.");
    b->dados[MARCOS].capitulos[6].versos[23] = wxT("E jurou-lhe, dizendo: Tudo o que me pedires te darei, ainda que seja metade do meu reino.");
    b->dados[MARCOS].capitulos[6].versos[24] = wxT("Tendo ela saído, perguntou a sua mãe: Que pedirei? Ela respondeu: A cabeça de João, o Batista.");
    b->dados[MARCOS].capitulos[6].versos[25] = wxT("E tornando logo com pressa à presença do rei, pediu, dizendo: Quero que imediatamente me dês num prato a cabeça de João, o Batista.");
    b->dados[MARCOS].capitulos[6].versos[26] = wxT("Ora, entristeceu-se muito o rei; todavia, por causa dos seus juramentos e por causa dos que estavam à mesa, não lha quis negar.");
    b->dados[MARCOS].capitulos[6].versos[27] = wxT("O rei, pois, enviou logo um soldado da sua guarda com ordem de trazer a cabeça de João. Então ele foi e o degolou no cárcere,");
    b->dados[MARCOS].capitulos[6].versos[28] = wxT("e trouxe a cabeça num prato e a deu à jovem, e a jovem a deu à sua mãe.");
    b->dados[MARCOS].capitulos[6].versos[29] = wxT("Quando os seus discípulos ouviram isso, vieram, tomaram o seu corpo e o puseram num sepulcro.");
    b->dados[MARCOS].capitulos[6].versos[30] = wxT("Reuniram-se os apóstolos com Jesus e contaram-lhe tudo o que tinham feito e ensinado.");
    b->dados[MARCOS].capitulos[6].versos[31] = wxT("Ao que ele lhes disse: Vinde vós, à parte, para um lugar deserto, e descansai um pouco. Porque eram muitos os que vinham e iam, e não tinham tempo nem para comer.");
    b->dados[MARCOS].capitulos[6].versos[32] = wxT("Retiraram-se, pois, no barco para um lugar deserto, à parte.");
    b->dados[MARCOS].capitulos[6].versos[33] = wxT("Muitos, porém, os viram partir, e os reconheceram; e para lá correram a pé de todas as cidades, e ali chegaram primeiro do que eles.");
    b->dados[MARCOS].capitulos[6].versos[34] = wxT("E Jesus, ao desembarcar, viu uma grande multidão e compadeceu-se deles, porque eram como ovelhas que não têm pastor; e começou a ensinar-lhes muitas coisas.");
    b->dados[MARCOS].capitulos[6].versos[35] = wxT("Estando a hora já muito adiantada, aproximaram-se dele seus discípulos e disseram: O lugar é deserto, e a hora já está muito adiantada;");
    b->dados[MARCOS].capitulos[6].versos[36] = wxT("despede-os, para que vão aos sítios e às aldeias, em redor, e comprem para si o que comer.");
    b->dados[MARCOS].capitulos[6].versos[37] = wxT("Ele, porém, lhes respondeu: Dai-lhes vós de comer. Então eles lhe perguntaram: Havemos de ir comprar duzentos denários de pão e dar-lhes de comer?");
    b->dados[MARCOS].capitulos[6].versos[38] = wxT("Ao que ele lhes disse: Quantos pães tendes? Ide ver. E, tendo-se informado, responderam: Cinco pães e dois peixes.");
    b->dados[MARCOS].capitulos[6].versos[39] = wxT("Então lhes ordenou que a todos fizessem reclinar-se, em grupos, sobre a relva verde.");
    b->dados[MARCOS].capitulos[6].versos[40] = wxT("E reclinaram-se em grupos de cem e de cinqüenta.");
    b->dados[MARCOS].capitulos[6].versos[41] = wxT("E tomando os cinco pães e os dois peixes, e erguendo os olhos ao céu, os abençoou; partiu os pães e os entregava a seus discípulos para lhos servirem; também repartiu os dois peixes por todos.");
    b->dados[MARCOS].capitulos[6].versos[42] = wxT("E todos comeram e se fartaram.");
    b->dados[MARCOS].capitulos[6].versos[43] = wxT("Em seguida, recolheram doze cestos cheios dos pedaços de pão e de peixe.");
    b->dados[MARCOS].capitulos[6].versos[44] = wxT("Ora, os que comeram os pães eram cinco mil homens.");
    b->dados[MARCOS].capitulos[6].versos[45] = wxT("Logo em seguida obrigou os seus discípulos a entrar no barco e passar adiante, para o outro lado, a Betsaida, enquanto ele despedia a multidão.");
    b->dados[MARCOS].capitulos[6].versos[46] = wxT("E, tendo-a despedido, foi ao monte para orar.");
    b->dados[MARCOS].capitulos[6].versos[47] = wxT("Chegada a tardinha, estava o barco no meio do mar, e ele sozinho em terra.");
    b->dados[MARCOS].capitulos[6].versos[48] = wxT("E, vendo-os fatigados a remar, porque o vento lhes era contrário, pela quarta vigília da noite, foi ter com eles, andando sobre o mar; e queria passar-lhes adiante;");
    b->dados[MARCOS].capitulos[6].versos[49] = wxT("eles, porém, ao vê-lo andando sobre o mar, pensaram que era um fantasma e gritaram;");
    b->dados[MARCOS].capitulos[6].versos[50] = wxT("porque todos o viram e se assustaram; mas ele imediatamente falou com eles e disse-lhes: Tende ânimo; sou eu; não temais.");
    b->dados[MARCOS].capitulos[6].versos[51] = wxT("E subiu para junto deles no barco, e o vento cessou; e ficaram, no seu íntimo, grandemente pasmados;");
    b->dados[MARCOS].capitulos[6].versos[52] = wxT("pois não tinham compreendido o milagre dos pães, antes o seu coração estava endurecido.");
    b->dados[MARCOS].capitulos[6].versos[53] = wxT("E, terminada a travessia, chegaram à terra em Genezaré, e ali atracaram.");
    b->dados[MARCOS].capitulos[6].versos[54] = wxT("Logo que desembarcaram, o povo reconheceu a Jesus;");
    b->dados[MARCOS].capitulos[6].versos[55] = wxT("e correndo eles por toda aquela região, começaram a levar nos leitos os que se achavam enfermos, para onde ouviam dizer que ele estava.");
    b->dados[MARCOS].capitulos[6].versos[56] = wxT("Onde quer, pois, que entrava, fosse nas aldeias, nas cidades ou nos campos, apresentavam os enfermos nas praças, e rogavam-lhe que os deixasse tocar ao menos a orla do seu manto; e todos os que a tocavam ficavam curados.");

    b->dados[MARCOS].capitulos[7].versos[1] = wxT("Foram ter com Jesus os fariseus, e alguns dos escribas vindos de Jerusalém,");
    b->dados[MARCOS].capitulos[7].versos[2] = wxT("e repararam que alguns dos seus discípulos comiam pão com as mãos impuras, isto é, por lavar.");
    b->dados[MARCOS].capitulos[7].versos[3] = wxT("Pois os fariseus, e todos os judeus, guardando a tradição dos anciãos, não comem sem lavar as mãos cuidadosamente;");
    b->dados[MARCOS].capitulos[7].versos[4] = wxT("e quando voltam do mercado, se não se purificarem, não comem. E muitas outras coisas há que receberam para observar, como a lavagem de copos, de jarros e de vasos de bronze.");
    b->dados[MARCOS].capitulos[7].versos[5] = wxT("Perguntaram-lhe, pois, os fariseus e os escribas: Por que não andam os teus discípulos conforme a tradição dos anciãos, mas comem o pão com as mãos por lavar?");
    b->dados[MARCOS].capitulos[7].versos[6] = wxT("Respondeu-lhes: Bem profetizou Isaías acerca de vós, hipócritas, como está escrito: Este povo honra-me com os lábios; o seu coração, porém, está longe de mim;");
    b->dados[MARCOS].capitulos[7].versos[7] = wxT("mas em vão me adoram, ensinando doutrinas que são preceitos de homens.");
    b->dados[MARCOS].capitulos[7].versos[8] = wxT("Vós deixais o mandamento de Deus, e vos apegais à tradição dos homens.");
    b->dados[MARCOS].capitulos[7].versos[9] = wxT("Disse-lhes ainda: Bem sabeis rejeitar o mandamento de Deus, para guardardes a vossa tradição.");
    b->dados[MARCOS].capitulos[7].versos[10] = wxT("Pois Moisés disse: Honra a teu pai e a tua mãe; e: Quem maldisser ao pai ou à mãe, certamente morrerá.");
    b->dados[MARCOS].capitulos[7].versos[11] = wxT("Mas vós dizeis: Se um homem disser a seu pai ou a sua mãe: Aquilo que poderias aproveitar de mim é Corbã, isto é, oferta ao Senhor,");
    b->dados[MARCOS].capitulos[7].versos[12] = wxT("não mais lhe permitis fazer coisa alguma por seu pai ou por sua mãe,");
    b->dados[MARCOS].capitulos[7].versos[13] = wxT("invalidando assim a palavra de Deus pela vossa tradição que vós transmitistes; também muitas outras coisas semelhantes fazeis.");
    b->dados[MARCOS].capitulos[7].versos[14] = wxT("E chamando a si outra vez a multidão, disse-lhes: Ouvi-me vós todos, e entendei.");
    b->dados[MARCOS].capitulos[7].versos[15] = wxT("Nada há fora do homem que, entrando nele, possa contaminá-lo; mas o que sai do homem, isso é que o contamina.");
    b->dados[MARCOS].capitulos[7].versos[16] = wxT("{Se alguém tem ouvidos para ouvir, ouça.}");
    b->dados[MARCOS].capitulos[7].versos[17] = wxT("Depois, quando deixou a multidão e entrou em casa, os seus discípulos o interrogaram acerca da parábola.");
    b->dados[MARCOS].capitulos[7].versos[18] = wxT("Respondeu-lhes ele: Assim também vós estais sem entender? Não compreendeis que tudo o que de fora entra no homem não o pode contaminar,");
    b->dados[MARCOS].capitulos[7].versos[19] = wxT("porque não lhe entra no coração, mas no ventre, e é lançado fora? Assim declarou puros todos os alimentos.");
    b->dados[MARCOS].capitulos[7].versos[20] = wxT("E prosseguiu: O que sai do homem , isso é que o contamina.");
    b->dados[MARCOS].capitulos[7].versos[21] = wxT("Pois é do interior, do coração dos homens, que procedem os maus pensamentos, as prostituições, os furtos, os homicídios, os adultérios,");
    b->dados[MARCOS].capitulos[7].versos[22] = wxT("a cobiça, as maldades, o dolo, a libertinagem, a inveja, a blasfêmia, a soberba, a insensatez;");
    b->dados[MARCOS].capitulos[7].versos[23] = wxT("todas estas más coisas procedem de dentro e contaminam o homem.");
    b->dados[MARCOS].capitulos[7].versos[24] = wxT("Levantando-se dali, foi para as regiões de Tiro e Sidom. E entrando numa casa, não queria que ninguém o soubesse, mas não pode ocultar-se;");
    b->dados[MARCOS].capitulos[7].versos[25] = wxT("porque logo, certa mulher, cuja filha estava possessa de um espírito imundo, ouvindo falar dele, veio e prostrou-se-lhe aos pés;");
    b->dados[MARCOS].capitulos[7].versos[26] = wxT("{ora, a mulher era grega, de origem siro-fenícia} e rogava-lhe que expulsasse de sua filha o demônio.");
    b->dados[MARCOS].capitulos[7].versos[27] = wxT("Respondeu-lhes Jesus: Deixa que primeiro se fartem os filhos; porque não é bom tomar o pão dos filhos e lança-lo aos cachorrinhos.");
    b->dados[MARCOS].capitulos[7].versos[28] = wxT("Ela, porém, replicou, e disse-lhe: Sim, Senhor; mas também os cachorrinhos debaixo da mesa comem das migalhas dos filhos.");
    b->dados[MARCOS].capitulos[7].versos[29] = wxT("Então ele lhe disse: Por essa palavra, vai; o demônio já saiu de tua filha.");
    b->dados[MARCOS].capitulos[7].versos[30] = wxT("E, voltando ela para casa, achou a menina deitada sobre a cama, e que o demônio já havia saído.");
    b->dados[MARCOS].capitulos[7].versos[31] = wxT("Tendo Jesus partido das regiões de Tiro, foi por Sidom até o mar da Galiléia, passando pelas regiões de Decápolis.");
    b->dados[MARCOS].capitulos[7].versos[32] = wxT("E trouxeram-lhe um surdo, que falava dificilmente; e rogaram-lhe que pusesse a mão sobre ele.");
    b->dados[MARCOS].capitulos[7].versos[33] = wxT("Jesus, pois, tirou-o de entre a multidão, à parte, meteu-lhe os dedos nos ouvidos e, cuspindo, tocou-lhe na língua;");
    b->dados[MARCOS].capitulos[7].versos[34] = wxT("e erguendo os olhos ao céu, suspirou e disse-lhe: Efatá; isto é Abre-te.");
    b->dados[MARCOS].capitulos[7].versos[35] = wxT("E abriram-se-lhe os ouvidos, a prisão da língua se desfez, e falava perfeitamente.");
    b->dados[MARCOS].capitulos[7].versos[36] = wxT("Então lhes ordenou Jesus que a ninguém o dissessem; mas, quando mais lho proibia, tanto mais o divulgavam.");
    b->dados[MARCOS].capitulos[7].versos[37] = wxT("E se maravilhavam sobremaneira, dizendo: Tudo tem feito bem; faz até os surdos ouvir e os mudos falar.");

    b->dados[MARCOS].capitulos[8].versos[1] = wxT("Naqueles dias, havendo de novo uma grande multidão, e não tendo o que comer, chamou Jesus os discípulos e disse-lhes:");
    b->dados[MARCOS].capitulos[8].versos[2] = wxT("Tenho compaixão da multidão, porque já faz três dias que eles estão comigo, e não têm o que comer.");
    b->dados[MARCOS].capitulos[8].versos[3] = wxT("Se eu os mandar em jejum para suas casas, desfalecerão no caminho; e alguns deles vieram de longe.");
    b->dados[MARCOS].capitulos[8].versos[4] = wxT("E seus discípulos lhe responderam: Donde poderá alguém satisfazê-los de pão aqui no deserto?");
    b->dados[MARCOS].capitulos[8].versos[5] = wxT("Perguntou-lhes Jesus: Quantos pães tendes? Responderam: Sete.");
    b->dados[MARCOS].capitulos[8].versos[6] = wxT("Logo mandou ao povo que se sentasse no chão; e tomando os sete pães e havendo dado graças, partiu-os e os entregava a seus discípulos para que os distribuíssem; e eles os distribuíram pela multidão.");
    b->dados[MARCOS].capitulos[8].versos[7] = wxT("Tinham também alguns peixinhos, os quais ele abençoou, e mandou que estes também fossem distribuídos.");
    b->dados[MARCOS].capitulos[8].versos[8] = wxT("Comeram, pois, e se fartaram; e dos pedaços que sobejavam levantaram sete alcofas.");
    b->dados[MARCOS].capitulos[8].versos[9] = wxT("Ora, eram cerca de quatro mil homens. E Jesus os despediu.");
    b->dados[MARCOS].capitulos[8].versos[10] = wxT("E, entrando logo no barco com seus discípulos, foi para as regiões de Dalmanuta.");
    b->dados[MARCOS].capitulos[8].versos[11] = wxT("Saíram os fariseus e começaram a discutir com ele, pedindo-lhe um sinal do céu, para o experimentarem.");
    b->dados[MARCOS].capitulos[8].versos[12] = wxT("Ele, suspirando profundamente em seu espírito, disse: Por que pede esta geração um sinal? Em verdade vos digo que a esta geração não será dado sinal algum.");
    b->dados[MARCOS].capitulos[8].versos[13] = wxT("E, deixando-os, tornou a embarcar e foi para o outro lado.");
    b->dados[MARCOS].capitulos[8].versos[14] = wxT("Ora, eles se esqueceram de levar pão, e no barco não tinham consigo senão um pão.");
    b->dados[MARCOS].capitulos[8].versos[15] = wxT("E Jesus ordenou-lhes, dizendo: Olhai, guardai-vos do fermento dos fariseus e do fermento de Herodes.");
    b->dados[MARCOS].capitulos[8].versos[16] = wxT("Pelo que eles arrazoavam entre si porque não tinham pão.");
    b->dados[MARCOS].capitulos[8].versos[17] = wxT("E Jesus, percebendo isso, disse-lhes: Por que arrazoais por não terdes pão? não compreendeis ainda, nem entendeis? tendes o vosso coração endurecido?");
    b->dados[MARCOS].capitulos[8].versos[18] = wxT("Tendo olhos, não vedes? e tendo ouvidos, não ouvis? e não vos lembrais?");
    b->dados[MARCOS].capitulos[8].versos[19] = wxT("Quando parti os cinco pães para os cinco mil, quantos cestos cheios de pedaços levantastes? Responderam-lhe: Doze.");
    b->dados[MARCOS].capitulos[8].versos[20] = wxT("E quando parti os sete para os quatro mil, quantas alcofas cheias de pedaços levantastes? Responderam-lhe: Sete.");
    b->dados[MARCOS].capitulos[8].versos[21] = wxT("E ele lhes disse: Não entendeis ainda?");
    b->dados[MARCOS].capitulos[8].versos[22] = wxT("Então chegaram a Betsaída. E trouxeram-lhe um cego, e rogaram-lhe que o tocasse.");
    b->dados[MARCOS].capitulos[8].versos[23] = wxT("Jesus, pois, tomou o cego pela mão, e o levou para fora da aldeia; e cuspindo-lhe nos olhos, e impondo-lhe as mãos, perguntou-lhe: Vês alguma coisa?");
    b->dados[MARCOS].capitulos[8].versos[24] = wxT("E, levantando ele os olhos, disse: Estou vendo os homens; porque como árvores os vejo andando.");
    b->dados[MARCOS].capitulos[8].versos[25] = wxT("Então tornou a pôr-lhe as mãos sobre os olhos; e ele, olhando atentamente, ficou restabelecido, pois já via nitidamente todas as coisas.");
    b->dados[MARCOS].capitulos[8].versos[26] = wxT("Depois o mandou para casa, dizendo: Mas não entres na aldeia.");
    b->dados[MARCOS].capitulos[8].versos[27] = wxT("E saiu Jesus com os seus discípulos para as aldeias de Cesaréia de Filipe, e no caminho interrogou os discípulos, dizendo: Quem dizem os homens que eu sou?");
    b->dados[MARCOS].capitulos[8].versos[28] = wxT("Responderam-lhe eles: Uns dizem: João, o Batista; outros: Elias; e ainda outros: Algum dos profetas.");
    b->dados[MARCOS].capitulos[8].versos[29] = wxT("Então lhes perguntou: Mas vós, quem dizeis que eu sou? Respondendo, Pedro lhe disse: Tu és o Cristo.");
    b->dados[MARCOS].capitulos[8].versos[30] = wxT("E ordenou-lhes Jesus que a ninguém dissessem aquilo a respeito dele.");
    b->dados[MARCOS].capitulos[8].versos[31] = wxT("Começou então a ensinar-lhes que era necessário que o Filho do homem padecesse muitas coisas, que fosse rejeitado pelos anciãos e principais sacerdotes e pelos escribas, que fosse morto, e que depois de três dias ressurgisse.");
    b->dados[MARCOS].capitulos[8].versos[32] = wxT("E isso dizia abertamente. Ao que Pedro, tomando-o à parte, começou a repreendê-lo.");
    b->dados[MARCOS].capitulos[8].versos[33] = wxT("Mas ele, virando-se olhando para seus discípulos, repreendeu a Pedro, dizendo: Para trás de mim, Satanás; porque não cuidas das coisas que são de Deus, mas sim das que são dos homens.");
    b->dados[MARCOS].capitulos[8].versos[34] = wxT("E chamando a si a multidão com os discípulos, disse-lhes: Se alguém quer vir após mim, negue-se a si mesmo, tome a sua cruz, e siga-me.");
    b->dados[MARCOS].capitulos[8].versos[35] = wxT("Pois quem quiser salvar a sua vida, perdê-la-á; mas quem perder a sua vida por amor de mim e do evangelho, salvá-la-á.");
    b->dados[MARCOS].capitulos[8].versos[36] = wxT("Pois que aproveita ao homem ganhar o mundo inteiro e perder a sua vida?");
    b->dados[MARCOS].capitulos[8].versos[37] = wxT("Ou que diria o homem em troca da sua vida?");
    b->dados[MARCOS].capitulos[8].versos[38] = wxT("Porquanto, qualquer que, entre esta geração adúltera e pecadora, se envergonhar de mim e das minhas palavras, também dele se envergonhará o Filho do homem quando vier na glória de seu Pai com os santos anjos.");

    b->dados[MARCOS].capitulos[9].versos[1] = wxT("Disse-lhes mais: Em verdade vos digo que, dos que aqui estão, alguns há que de modo nenhum provarão a morte até que vejam o reino de Deus já chegando com poder.");
    b->dados[MARCOS].capitulos[9].versos[2] = wxT("Seis dias depois tomou Jesus consigo a Pedro, a Tiago, e a João, e os levou à parte sós, a um alto monte; e foi transfigurado diante deles;");
    b->dados[MARCOS].capitulos[9].versos[3] = wxT("as suas vestes tornaram-se resplandecentes, extremamente brancas, tais como nenhum lavandeiro sobre a terra as poderia branquear.");
    b->dados[MARCOS].capitulos[9].versos[4] = wxT("E apareceu-lhes Elias com Moisés, e falavam com Jesus.");
    b->dados[MARCOS].capitulos[9].versos[5] = wxT("Pedro, tomando a palavra, disse a Jesus: Mestre, bom é estarmos aqui; façamos, pois, três cabanas, uma para ti, outra para Moisés, e outra para Elias.");
    b->dados[MARCOS].capitulos[9].versos[6] = wxT("Pois não sabia o que havia de dizer, porque ficaram atemorizados.");
    b->dados[MARCOS].capitulos[9].versos[7] = wxT("Nisto veio uma nuvem que os cobriu, e dela saiu uma voz que dizia: Este é o meu Filho amado; a ele ouvi.");
    b->dados[MARCOS].capitulos[9].versos[8] = wxT("De repente, tendo olhado em redor, não viram mais a ninguém consigo, senão só a Jesus.");
    b->dados[MARCOS].capitulos[9].versos[9] = wxT("Enquanto desciam do monte, ordenou-lhes que a ninguém contassem o que tinham visto, até que o Filho do homem ressurgisse dentre os mortos.");
    b->dados[MARCOS].capitulos[9].versos[10] = wxT("E eles guardaram o caso em segredo, indagando entre si o que seria o ressurgir dentre os mortos.");
    b->dados[MARCOS].capitulos[9].versos[11] = wxT("Então lhe perguntaram: Por que dizem os escribas que é necessário que Elias venha primeiro?");
    b->dados[MARCOS].capitulos[9].versos[12] = wxT("Respondeu-lhes Jesus: Na verdade Elias havia de vir primeiro, a restaurar todas as coisas; e como é que está escrito acerca do Filho do homem que ele deva padecer muito a ser aviltado?");
    b->dados[MARCOS].capitulos[9].versos[13] = wxT("Digo-vos, porém, que Elias já veio, e fizeram-lhe tudo quanto quiseram, como dele está escrito.");
    b->dados[MARCOS].capitulos[9].versos[14] = wxT("Quando chegaram aonde estavam os discípulos, viram ao redor deles uma grande multidão, e alguns escribas a discutirem com eles.");
    b->dados[MARCOS].capitulos[9].versos[15] = wxT("E logo toda a multidão, vendo a Jesus, ficou grandemente surpreendida; e correndo todos para ele, o saudavam.");
    b->dados[MARCOS].capitulos[9].versos[16] = wxT("Perguntou ele aos escribas: Que é que discutis com eles?");
    b->dados[MARCOS].capitulos[9].versos[17] = wxT("Respondeu-lhe um dentre a multidão: Mestre, eu te trouxe meu filho, que tem um espírito mudo;");
    b->dados[MARCOS].capitulos[9].versos[18] = wxT("e este, onde quer que o apanha, convulsiona-o, de modo que ele espuma, range os dentes, e vai definhando; e eu pedi aos teus discípulos que o expulsassem, e não puderam.");
    b->dados[MARCOS].capitulos[9].versos[19] = wxT("Ao que Jesus lhes respondeu: ó geração incrédula! até quando estarei convosco? até quando vos hei de suportar? Trazei-mo.");
    b->dados[MARCOS].capitulos[9].versos[20] = wxT("Então lho trouxeram; e quando ele viu a Jesus, o espírito imediatamente o convulsionou; e o endemoninhado, caindo por terra, revolvia-se espumando.");
    b->dados[MARCOS].capitulos[9].versos[21] = wxT("E perguntou Jesus ao pai dele: Há quanto tempo sucede-lhe isto? Respondeu ele: Desde a infância;");
    b->dados[MARCOS].capitulos[9].versos[22] = wxT("e muitas vezes o tem lançado no fogo, e na água, para o destruir; mas se podes fazer alguma coisa, tem compaixão de nós e ajuda-nos.");
    b->dados[MARCOS].capitulos[9].versos[23] = wxT("Ao que lhe disse Jesus: Se podes!-tudo é possível ao que crê.");
    b->dados[MARCOS].capitulos[9].versos[24] = wxT("Imediatamente o pai do menino, clamando, {com lágrimas} disse: Creio! Ajuda a minha incredulidade.");
    b->dados[MARCOS].capitulos[9].versos[25] = wxT("E Jesus, vendo que a multidão, correndo, se aglomerava, repreendeu o espírito imundo, dizendo: Espírito mudo e surdo, eu te ordeno: Sai dele, e nunca mais entres nele.");
    b->dados[MARCOS].capitulos[9].versos[26] = wxT("E ele, gritando, e agitando-o muito, saiu; e ficou o menino como morto, de modo que a maior parte dizia: Morreu.");
    b->dados[MARCOS].capitulos[9].versos[27] = wxT("Mas Jesus, tomando-o pela mão, o ergueu; e ele ficou em pé.");
    b->dados[MARCOS].capitulos[9].versos[28] = wxT("E quando entrou em casa, seus discípulos lhe perguntaram à parte: Por que não pudemos nós expulsá-lo?");
    b->dados[MARCOS].capitulos[9].versos[29] = wxT("Respondeu-lhes: Esta casta não sai de modo algum, salvo à força de oração {e jejum.}");
    b->dados[MARCOS].capitulos[9].versos[30] = wxT("Depois, tendo partido dali, passavam pela Galiléia, e ele não queria que ninguém o soubesse;");
    b->dados[MARCOS].capitulos[9].versos[31] = wxT("porque ensinava a seus discípulos, e lhes dizia: O Filho do homem será entregue nas mãos dos homens, que o matarão; e morto ele, depois de três dias ressurgirá.");
    b->dados[MARCOS].capitulos[9].versos[32] = wxT("Mas eles não entendiam esta palavra, e temiam interrogá-lo.");
    b->dados[MARCOS].capitulos[9].versos[33] = wxT("Chegaram a Cafarnaum. E estando ele em casa, perguntou-lhes: Que estáveis discutindo pelo caminho?");
    b->dados[MARCOS].capitulos[9].versos[34] = wxT("Mas eles se calaram, porque pelo caminho haviam discutido entre si qual deles era o maior.");
    b->dados[MARCOS].capitulos[9].versos[35] = wxT("E ele, sentando-se, chamou os doze e lhes disse: se alguém quiser ser o primeiro, será o derradeiro de todos e o servo de todos.");
    b->dados[MARCOS].capitulos[9].versos[36] = wxT("Então tomou uma criança, pô-la no meio deles e, abraçando-a, disse-lhes:");
    b->dados[MARCOS].capitulos[9].versos[37] = wxT("Qualquer que em meu nome receber uma destas crianças, a mim me recebe; e qualquer que me recebe a mim, recebe não a mim mas àquele que me enviou.");
    b->dados[MARCOS].capitulos[9].versos[38] = wxT("Disse-lhe João: Mestre, vimos um homem que em teu nome expulsava demônios, e nós lho proibimos, porque não nos seguia.");
    b->dados[MARCOS].capitulos[9].versos[39] = wxT("Jesus, porém, respondeu: Não lho proibais; porque ninguém há que faça milagre em meu nome e possa logo depois falar mal de mim;");
    b->dados[MARCOS].capitulos[9].versos[40] = wxT("pois quem não é contra nós, é por nós.");
    b->dados[MARCOS].capitulos[9].versos[41] = wxT("Porquanto qualquer que vos der a beber um copo de água em meu nome, porque sois de Cristo, em verdade vos digo que de modo algum perderá a sua recompensa.");
    b->dados[MARCOS].capitulos[9].versos[42] = wxT("Mas qualquer que fizer tropeçar um destes pequeninos que crêem em mim, melhor lhe fora que se lhe pendurasse ao pescoço uma pedra de moinho, e que fosse lançado no mar.");
    b->dados[MARCOS].capitulos[9].versos[43] = wxT("E se a tua mão te fizer tropeçar, corta-a; melhor é entrares na vida aleijado, do que, tendo duas mãos, ires para o inferno, para o fogo que nunca se apaga.");
    b->dados[MARCOS].capitulos[9].versos[44] = wxT("{onde o seu verme não morre, e o fogo não se apaga.}");
    b->dados[MARCOS].capitulos[9].versos[45] = wxT("Ou, se o teu pé te fizer tropeçar, corta-o; melhor é entrares coxo na vida, do que, tendo dois pés, seres lançado no inferno.");
    b->dados[MARCOS].capitulos[9].versos[46] = wxT("{onde o seu verme não morre, e o fogo não se apaga.}");
    b->dados[MARCOS].capitulos[9].versos[47] = wxT("Ou, se o teu olho te fizer tropeçar, lança-o fora; melhor é entrares no reino de Deus com um só olho, do que, tendo dois olhos, seres lançado no inferno.");
    b->dados[MARCOS].capitulos[9].versos[48] = wxT("onde o seu verme não morre, e o fogo não se apaga.");
    b->dados[MARCOS].capitulos[9].versos[49] = wxT("Porque cada um será salgado com fogo.");
    b->dados[MARCOS].capitulos[9].versos[50] = wxT("Bom é o sal; mas, se o sal se tornar insípido, com que o haveis de temperar? Tende sal em vós mesmos, e guardai a paz uns com os outros.");

    b->dados[MARCOS].capitulos[10].versos[1] = wxT("Levantando-se Jesus, partiu dali para os termos da Judéia, e para além do Jordão; e do novo as multidões se reuniram em torno dele; e tornou a ensiná-las, como tinha por costume.");
    b->dados[MARCOS].capitulos[10].versos[2] = wxT("Então se aproximaram dele alguns fariseus e, para o experimentarem, lhe perguntaram: É lícito ao homem repudiar sua mulher?");
    b->dados[MARCOS].capitulos[10].versos[3] = wxT("Ele, porém, respondeu-lhes: Que vos ordenou Moisés?");
    b->dados[MARCOS].capitulos[10].versos[4] = wxT("Replicaram eles: Moisés permitiu escrever carta de divórcio, e repudiar a mulher.");
    b->dados[MARCOS].capitulos[10].versos[5] = wxT("Disse-lhes Jesus: Pela dureza dos vossos corações ele vos deixou escrito esse mandamento.");
    b->dados[MARCOS].capitulos[10].versos[6] = wxT("Mas desde o princípio da criação, Deus os fez homem e mulher.");
    b->dados[MARCOS].capitulos[10].versos[7] = wxT("Por isso deixará o homem a seu pai e a sua mãe, {e unir-se-á à sua mulher,}");
    b->dados[MARCOS].capitulos[10].versos[8] = wxT("e serão os dois uma só carne; assim já não são mais dois, mas uma só carne.");
    b->dados[MARCOS].capitulos[10].versos[9] = wxT("Porquanto o que Deus ajuntou, não o separe o homem.");
    b->dados[MARCOS].capitulos[10].versos[10] = wxT("Em casa os discípulos interrogaram-no de novo sobre isso.");
    b->dados[MARCOS].capitulos[10].versos[11] = wxT("Ao que lhes respondeu: Qualquer que repudiar sua mulher e casar com outra comete adultério contra ela;");
    b->dados[MARCOS].capitulos[10].versos[12] = wxT("e se ela repudiar seu marido e casar com outro, comete adultério.");
    b->dados[MARCOS].capitulos[10].versos[13] = wxT("Então lhe traziam algumas crianças para que as tocasse; mas os discípulos o repreenderam.");
    b->dados[MARCOS].capitulos[10].versos[14] = wxT("Jesus, porém, vendo isto, indignou-se e disse-lhes: Deixai vir a mim as crianças, e não as impeçais, porque de tais é o reino de Deus.");
    b->dados[MARCOS].capitulos[10].versos[15] = wxT("Em verdade vos digo que qualquer que não receber o reino de Deus como criança, de maneira nenhuma entrará nele.");
    b->dados[MARCOS].capitulos[10].versos[16] = wxT("E, tomando-as nos seus braços, as abençoou, pondo as mãos sobre elas.");
    b->dados[MARCOS].capitulos[10].versos[17] = wxT("Ora, ao sair para se pôr a caminho, correu para ele um homem, o qual se ajoelhou diante dele e lhe perguntou: Bom Mestre, que hei de fazer para herdar a vida eterna?");
    b->dados[MARCOS].capitulos[10].versos[18] = wxT("Respondeu-lhe Jesus: Por que me chamas bom? ninguém é bom, senão um que é Deus.");
    b->dados[MARCOS].capitulos[10].versos[19] = wxT("Sabes os mandamentos: Não matarás; não adulterarás; não furtarás; não dirás falso testemunho; a ninguém defraudarás; honra a teu pai e a tua mãe.");
    b->dados[MARCOS].capitulos[10].versos[20] = wxT("Ele, porém, lhe replicou: Mestre, tudo isso tenho guardado desde a minha juventude.");
    b->dados[MARCOS].capitulos[10].versos[21] = wxT("E Jesus, olhando para ele, o amou e lhe disse: Uma coisa te falta; vai vende tudo quanto tens e dá-o aos pobres, e terás um tesouro no céu; e vem, segue-me.");
    b->dados[MARCOS].capitulos[10].versos[22] = wxT("Mas ele, pesaroso desta palavra, retirou-se triste, porque possuía muitos bens.");
    b->dados[MARCOS].capitulos[10].versos[23] = wxT("Então Jesus, olhando em redor, disse aos seus discípulos: Quão dificilmente entrarão no reino de Deus os que têm riquezas!");
    b->dados[MARCOS].capitulos[10].versos[24] = wxT("E os discípulos se maravilharam destas suas palavras; mas Jesus, tornando a falar, disse-lhes: Filhos, quão difícil é {para os que confiam nas riquezas} entrar no reino de Deus!");
    b->dados[MARCOS].capitulos[10].versos[25] = wxT("É mais fácil um camelo passar pelo fundo de uma agulha, do que entrar um rico no reino de Deus.");
    b->dados[MARCOS].capitulos[10].versos[26] = wxT("Com isso eles ficaram sobremaneira maravilhados, dizendo entre si: Quem pode, então, ser salvo?");
    b->dados[MARCOS].capitulos[10].versos[27] = wxT("Jesus, fixando os olhos neles, respondeu: Para os homens é impossível, mas não para Deus; porque para Deus tudo é possível.");
    b->dados[MARCOS].capitulos[10].versos[28] = wxT("Pedro começou a dizer-lhe: Eis que nós deixamos tudo e te seguimos.");
    b->dados[MARCOS].capitulos[10].versos[29] = wxT("Respondeu Jesus: Em verdade vos digo que ninguém há, que tenha deixado casa, ou irmãos, ou irmãs, ou mãe, ou pai, ou filhos, ou campos, por amor de mim e do evangelho,");
    b->dados[MARCOS].capitulos[10].versos[30] = wxT("que não receba cem vezes tanto, já neste tempo, em casas, e irmãos, e irmãs, e mães, e filhos, e campos, com perseguições; e no mundo vindouro a vida eterna.");
    b->dados[MARCOS].capitulos[10].versos[31] = wxT("Mas muitos que são primeiros serão últimos; e muitos que são últimos serão primeiros.");
    b->dados[MARCOS].capitulos[10].versos[32] = wxT("Ora, estavam a caminho, subindo para Jerusalém; e Jesus ia adiante deles, e eles se maravilhavam e o seguiam atemorizados. De novo tomou consigo os doze e começou a contar-lhes as coisas que lhe haviam de sobrevir,");
    b->dados[MARCOS].capitulos[10].versos[33] = wxT("dizendo: Eis que subimos a Jerusalém, e o Filho do homem será entregue aos principais sacerdotes e aos escribas; e eles o condenarão à morte, e o entregarão aos gentios;");
    b->dados[MARCOS].capitulos[10].versos[34] = wxT("e hão de escarnecê-lo e cuspir nele, e açoitá-lo, e matá-lo; e depois de três dias ressurgirá.");
    b->dados[MARCOS].capitulos[10].versos[35] = wxT("Nisso aproximaram-se dele Tiago e João, filhos de Zebedeu, dizendo-lhe: Mestre, queremos que nos faças o que te pedirmos.");
    b->dados[MARCOS].capitulos[10].versos[36] = wxT("Ele, pois, lhes perguntou: Que quereis que eu vos faça?");
    b->dados[MARCOS].capitulos[10].versos[37] = wxT("Responderam-lhe: Concede-nos que na tua glória nos sentemos, um à tua direita, e outro à tua esquerda.");
    b->dados[MARCOS].capitulos[10].versos[38] = wxT("Mas Jesus lhes disse: Não sabeis o que pedis; podeis beber o cálice que eu bebo, e ser batizados no batismo em que eu sou batizado?");
    b->dados[MARCOS].capitulos[10].versos[39] = wxT("E lhe responderam: Podemos. Mas Jesus lhes disse: O cálice que eu bebo, haveis de bebê-lo, e no batismo em que eu sou batizado, haveis de ser batizados;");
    b->dados[MARCOS].capitulos[10].versos[40] = wxT("mas o sentar-se à minha direita, ou à minha esquerda, não me pertence concedê-lo; mas isso é para aqueles a quem está reservado.");
    b->dados[MARCOS].capitulos[10].versos[41] = wxT("E ouvindo isso os dez, começaram a indignar-se contra Tiago e João.");
    b->dados[MARCOS].capitulos[10].versos[42] = wxT("Então Jesus chamou-os para junto de si e lhes disse: Sabeis que os que são reconhecidos como governadores dos gentios, deles se assenhoreiam, e que sobre eles os seus grandes exercem autoridade.");
    b->dados[MARCOS].capitulos[10].versos[43] = wxT("Mas entre vós não será assim; antes, qualquer que entre vós quiser tornar-se grande, será esse o que vos sirva;");
    b->dados[MARCOS].capitulos[10].versos[44] = wxT("e qualquer que entre vós quiser ser o primeiro, será servo de todos.");
    b->dados[MARCOS].capitulos[10].versos[45] = wxT("Pois também o Filho do homem não veio para ser servido, mas para servir, e para dar a sua vida em resgate de muitos.");
    b->dados[MARCOS].capitulos[10].versos[46] = wxT("Depois chegaram a Jericó. E, ao sair ele de Jericó com seus discípulos e uma grande multidão, estava sentado junto do caminho um mendigo cego, Bartimeu filho de Timeu.");
    b->dados[MARCOS].capitulos[10].versos[47] = wxT("Este, quando ouviu que era Jesus, o nazareno, começou a clamar, dizendo: Jesus, Filho de Davi, tem compaixão de mim!");
    b->dados[MARCOS].capitulos[10].versos[48] = wxT("E muitos o repreendiam, para que se calasse; mas ele clamava ainda mais: Filho de Davi, tem compaixão de mim.");
    b->dados[MARCOS].capitulos[10].versos[49] = wxT("Parou, pois, Jesus e disse: Chamai-o. E chamaram o cego, dizendo-lhe: Tem bom ânimo; levanta-te, ele te chama.");
    b->dados[MARCOS].capitulos[10].versos[50] = wxT("Nisto, lançando de si a sua capa, de um salto se levantou e foi ter com Jesus.");
    b->dados[MARCOS].capitulos[10].versos[51] = wxT("Perguntou-lhe o cego: Que queres que te faça? Respondeu-lhe o cego: Mestre, que eu veja.");
    b->dados[MARCOS].capitulos[10].versos[52] = wxT("Disse-lhe Jesus: Vai, a tua fé te salvou. E imediatamente recuperou a vista, e foi seguindo pelo caminho.");

    b->dados[MARCOS].capitulos[11].versos[1] = wxT("Ora, quando se aproximavam de Jerusalém, de Betfagé e de Betânia, junto do Monte das Oliveiras, enviou Jesus dois dos seus discípulos");
    b->dados[MARCOS].capitulos[11].versos[2] = wxT("e disse-lhes: Ide à aldeia que está defronte de vós; e logo que nela entrardes, encontrareis preso um jumentinho, em que ainda ninguém montou; desprendei-o e trazei-o.");
    b->dados[MARCOS].capitulos[11].versos[3] = wxT("E se alguém vos perguntar: Por que fazeis isso? respondei: O Senhor precisa dele, e logo tornará a enviá-lo para aqui.");
    b->dados[MARCOS].capitulos[11].versos[4] = wxT("Foram, pois, e acharam o jumentinho preso ao portão do lado de fora na rua, e o desprenderam.");
    b->dados[MARCOS].capitulos[11].versos[5] = wxT("E alguns dos que ali estavam lhes perguntaram: Que fazeis, desprendendo o jumentinho?");
    b->dados[MARCOS].capitulos[11].versos[6] = wxT("Responderam como Jesus lhes tinha mandado; e lho deixaram levar.");
    b->dados[MARCOS].capitulos[11].versos[7] = wxT("Então trouxeram a Jesus o jumentinho e lançaram sobre ele os seus mantos; e Jesus montou nele.");
    b->dados[MARCOS].capitulos[11].versos[8] = wxT("Muitos também estenderam pelo caminho os seus mantos, e outros, ramagens que tinham cortado nos campos.");
    b->dados[MARCOS].capitulos[11].versos[9] = wxT("E tanto os que o precediam como os que o seguiam, clamavam: Hosana! bendito o que vem em nome do Senhor!");
    b->dados[MARCOS].capitulos[11].versos[10] = wxT("Bendito o reino que vem, o reino de nosso pai Davi! Hosana nas alturas!");
    b->dados[MARCOS].capitulos[11].versos[11] = wxT("Tendo Jesus entrado em Jerusalém, foi ao templo; e tendo observado tudo em redor, como já fosse tarde, saiu para Betânia com os doze.");
    b->dados[MARCOS].capitulos[11].versos[12] = wxT("No dia seguinte, depois de saírem de Betânia teve fome,");
    b->dados[MARCOS].capitulos[11].versos[13] = wxT("e avistando de longe uma figueira que tinha folhas, foi ver se, porventura, acharia nela alguma coisa; e chegando a ela, nada achou senão folhas, porque não era tempo de figos.");
    b->dados[MARCOS].capitulos[11].versos[14] = wxT("E Jesus, falando, disse à figueira: Nunca mais coma alguém fruto de ti. E seus discípulos ouviram isso.");
    b->dados[MARCOS].capitulos[11].versos[15] = wxT("Chegaram, pois, a Jerusalém. E entrando ele no templo, começou a expulsar os que ali vendiam e compravam; e derribou as mesas dos cambistas, e as cadeiras dos que vendiam pombas;");
    b->dados[MARCOS].capitulos[11].versos[16] = wxT("e não consentia que ninguém atravessasse o templo levando qualquer utensílio;");
    b->dados[MARCOS].capitulos[11].versos[17] = wxT("e ensinava, dizendo-lhes: Não está escrito: A minha casa será chamada casa de oração para todas as nações? Vós, porém, a tendes feito covil de salteadores.");
    b->dados[MARCOS].capitulos[11].versos[18] = wxT("Ora, os principais sacerdotes e os escribas ouviram isto, e procuravam um modo de o matar; pois o temiam, porque toda a multidão se maravilhava da sua doutrina.");
    b->dados[MARCOS].capitulos[11].versos[19] = wxT("Ao cair da tarde, saíam da cidade.");
    b->dados[MARCOS].capitulos[11].versos[20] = wxT("Quando passavam na manhã seguinte, viram que a figueira tinha secado desde as raízes.");
    b->dados[MARCOS].capitulos[11].versos[21] = wxT("Então Pedro, lembrando-se, disse-lhe: Olha, Mestre, secou-se a figueira que amaldiçoaste.");
    b->dados[MARCOS].capitulos[11].versos[22] = wxT("Respondeu-lhes Jesus: Tende fé em Deus.");
    b->dados[MARCOS].capitulos[11].versos[23] = wxT("Em verdade vos digo que qualquer que disser a este monte: Ergue-te e lança-te no mar; e não duvidar em seu coração, mas crer que se fará aquilo que diz, assim lhe será feito.");
    b->dados[MARCOS].capitulos[11].versos[24] = wxT("Por isso vos digo que tudo o que pedirdes em oração, crede que o recebereis, e tê-lo-eis.");
    b->dados[MARCOS].capitulos[11].versos[25] = wxT("Quando estiverdes orando, perdoai, se tendes alguma coisa contra alguém, para que também vosso Pai que está no céu, vos perdoe as vossas ofensas.");
    b->dados[MARCOS].capitulos[11].versos[26] = wxT("{Mas, se vós não perdoardes, também vosso Pai, que está no céu, não vos perdoará as vossas ofensas.}");
    b->dados[MARCOS].capitulos[11].versos[27] = wxT("Vieram de novo a Jerusalém. E andando Jesus pelo templo, aproximaram-se dele os principais sacerdotes, os escribas e os anciãos,");
    b->dados[MARCOS].capitulos[11].versos[28] = wxT("que lhe perguntaram: Com que autoridade fazes tu estas coisas? ou quem te deu autoridade para fazê-las?");
    b->dados[MARCOS].capitulos[11].versos[29] = wxT("Respondeu-lhes Jesus: Eu vos perguntarei uma coisa; respondei-me, pois, e eu vos direi com que autoridade faço estas coisas.");
    b->dados[MARCOS].capitulos[11].versos[30] = wxT("O batismo de João era do céu, ou dos homens? respondei-me.");
    b->dados[MARCOS].capitulos[11].versos[31] = wxT("Ao que eles arrazoavam entre si: Se dissermos: Do céu, ele dirá: Então por que não o crestes?");
    b->dados[MARCOS].capitulos[11].versos[32] = wxT("Mas diremos, porventura: Dos homens?-É que temiam o povo; porque todos verdadeiramente tinham a João como profeta.");
    b->dados[MARCOS].capitulos[11].versos[33] = wxT("Responderam, pois, a Jesus: Não sabemos. Replicou-lhes ele: Nem eu vos digo com que autoridade faço estas coisas.");

    b->dados[MARCOS].capitulos[12].versos[1] = wxT("Então começou Jesus a falar-lhes por parábolas. Um homem plantou uma vinha, cercou-a com uma sebe, cavou um lagar, e edificou uma torre; depois arrendou-a a uns lavradores e ausentou-se do país.");
    b->dados[MARCOS].capitulos[12].versos[2] = wxT("No tempo próprio, enviou um servo aos lavradores para que deles recebesse do fruto da vinha.");
    b->dados[MARCOS].capitulos[12].versos[3] = wxT("Mas estes, apoderando-se dele, o espancaram e o mandaram embora de mãos vazias.");
    b->dados[MARCOS].capitulos[12].versos[4] = wxT("E tornou a enviar-lhes outro servo; e a este feriram na cabeça e o ultrajaram.");
    b->dados[MARCOS].capitulos[12].versos[5] = wxT("Então enviou ainda outro, e a este mataram; e a outros muitos, dos quais a uns espancaram e a outros mataram.");
    b->dados[MARCOS].capitulos[12].versos[6] = wxT("Ora, tinha ele ainda um, o seu filho amado; a este lhes enviou por último, dizendo: A meu filho terão respeito.");
    b->dados[MARCOS].capitulos[12].versos[7] = wxT("Mas aqueles lavradores disseram entre si: Este é o herdeiro; vinde, matemo-lo, e a herança será nossa.");
    b->dados[MARCOS].capitulos[12].versos[8] = wxT("E, agarrando-o, o mataram, e o lançaram fora da vinha.");
    b->dados[MARCOS].capitulos[12].versos[9] = wxT("Que fará, pois, o senhor da vinha? Virá e destruirá os lavradores, e dará a vinha a outros.");
    b->dados[MARCOS].capitulos[12].versos[10] = wxT("Nunca lestes esta escritura: A pedra que os edificadores rejeitaram, essa foi posta como pedra angular;");
    b->dados[MARCOS].capitulos[12].versos[11] = wxT("pelo Senhor foi feito isso, e é maravilhoso aos nossos olhos?");
    b->dados[MARCOS].capitulos[12].versos[12] = wxT("Procuravam então prendê-lo, mas temeram a multidão, pois perceberam que contra eles proferira essa parábola; e, deixando-o, se retiraram.");
    b->dados[MARCOS].capitulos[12].versos[13] = wxT("Enviaram-lhe então alguns dos fariseus e dos herodianos, para que o apanhassem em alguma palavra.");
    b->dados[MARCOS].capitulos[12].versos[14] = wxT("Aproximando-se, pois, disseram-lhe: Mestre, sabemos que és verdadeiro, e de ninguém se te dá; porque não olhas à aparência dos homens, mas ensinas segundo a verdade o caminho de Deus; é lícito dar tributo a César, ou não? Daremos, ou não daremos?");
    b->dados[MARCOS].capitulos[12].versos[15] = wxT("Mas Jesus, percebendo a hipocrisia deles, respondeu-lhes: Por que me experimentais? trazei-me um denário para que eu o veja.");
    b->dados[MARCOS].capitulos[12].versos[16] = wxT("E eles lho trouxeram. Perguntou-lhes Jesus: De quem é esta imagem e inscrição? Responderam-lhe: De César.");
    b->dados[MARCOS].capitulos[12].versos[17] = wxT("Disse-lhes Jesus: Dai, pois, a César o que é de César, e a Deus o que é de Deus. E admiravam-se dele.");
    b->dados[MARCOS].capitulos[12].versos[18] = wxT("Então se aproximaram dele alguns dos saduceus, que dizem não haver ressurreição, e lhe perguntaram, dizendo:");
    b->dados[MARCOS].capitulos[12].versos[19] = wxT("Mestre, Moisés nos deixou escrito que se morrer alguém, deixando mulher sem deixar filhos, o irmão dele case com a mulher, e suscite descendência ao irmão.");
    b->dados[MARCOS].capitulos[12].versos[20] = wxT("Ora, havia sete irmãos; o primeiro casou-se e morreu sem deixar descendência;");
    b->dados[MARCOS].capitulos[12].versos[21] = wxT("o segundo casou-se com a viúva, e morreu, não deixando descendência; e da mesma forma, o terceiro; e assim os sete, e não deixaram descendência.");
    b->dados[MARCOS].capitulos[12].versos[22] = wxT("Depois de todos, morreu também a mulher.");
    b->dados[MARCOS].capitulos[12].versos[23] = wxT("Na ressurreição, de qual deles será ela esposa, pois os sete por esposa a tiveram?");
    b->dados[MARCOS].capitulos[12].versos[24] = wxT("Respondeu-lhes Jesus: Porventura não errais vós em razão de não compreenderdes as Escrituras nem o poder de Deus?");
    b->dados[MARCOS].capitulos[12].versos[25] = wxT("Porquanto, ao ressuscitarem dos mortos, nem se casam, nem se dão em casamento; pelo contrário, são como os anjos nos céus.");
    b->dados[MARCOS].capitulos[12].versos[26] = wxT("Quanto aos mortos, porém, serem ressuscitados, não lestes no livro de Moisés, onde se fala da sarça, como Deus lhe disse: Eu sou o Deus de Abraão, o Deus de Isaque e o Deus de Jacó?");
    b->dados[MARCOS].capitulos[12].versos[27] = wxT("Ora, ele não é Deus de mortos, mas de vivos. Estais em grande erro.");
    b->dados[MARCOS].capitulos[12].versos[28] = wxT("Aproximou-se dele um dos escribas que os ouvira discutir e, percebendo que lhes havia respondido bem, perguntou-lhe: Qual é o primeiro de todos os mandamentos?");
    b->dados[MARCOS].capitulos[12].versos[29] = wxT("Respondeu Jesus: O primeiro é: Ouve, Israel, o Senhor nosso Deus é o único Senhor.");
    b->dados[MARCOS].capitulos[12].versos[30] = wxT("Amarás, pois, ao Senhor teu Deus de todo o teu coração, de toda a tua alma, de todo o teu entendimento e de todas as tuas forças.");
    b->dados[MARCOS].capitulos[12].versos[31] = wxT("E o segundo é este: Amarás ao teu próximo como a ti mesmo. Não há outro mandamento maior do que esses.");
    b->dados[MARCOS].capitulos[12].versos[32] = wxT("Ao que lhe disse o escriba: Muito bem, Mestre; com verdade disseste que ele é um, e fora dele não há outro;");
    b->dados[MARCOS].capitulos[12].versos[33] = wxT("e que amá-lo de todo o coração, de todo o entendimento e de todas as forças, e amar o próximo como a si mesmo, é mais do que todos os holocaustos e sacrifícios.");
    b->dados[MARCOS].capitulos[12].versos[34] = wxT("E Jesus, vendo que havia respondido sabiamente, disse-lhe: Não estás longe do reino de Deus. E ninguém ousava mais interrogá-lo.");
    b->dados[MARCOS].capitulos[12].versos[35] = wxT("Por sua vez, Jesus, enquanto ensinava no templo, perguntou: Como é que os escribas dizem que o Cristo é filho de Davi?");
    b->dados[MARCOS].capitulos[12].versos[36] = wxT("O próprio Davi falou, movido pelo Espírito Santo: Disse o Senhor ao meu Senhor: Assenta-te à minha direita, até que eu ponha os teus inimigos debaixo dos teus pés.");
    b->dados[MARCOS].capitulos[12].versos[37] = wxT("Davi mesmo lhe chama Senhor; como é ele seu filho? E a grande multidão o ouvia com prazer.");
    b->dados[MARCOS].capitulos[12].versos[38] = wxT("E prosseguindo ele no seu ensino, disse: Guardai-vos dos escribas, que gostam de andar com vestes compridas, e das saudações nas praças,");
    b->dados[MARCOS].capitulos[12].versos[39] = wxT("e dos primeiros assentos nas sinagogas, e dos primeiros lugares nos banquetes,");
    b->dados[MARCOS].capitulos[12].versos[40] = wxT("que devoram as casas das viúvas, e por pretexto fazem longas orações; estes hão de receber muito maior condenação.");
    b->dados[MARCOS].capitulos[12].versos[41] = wxT("E sentando-se Jesus defronte do cofre das ofertas, observava como a multidão lançava dinheiro no cofre; e muitos ricos deitavam muito.");
    b->dados[MARCOS].capitulos[12].versos[42] = wxT("Vindo, porém, uma pobre viúva, lançou dois leptos, que valiam um quadrante.");
    b->dados[MARCOS].capitulos[12].versos[43] = wxT("E chamando ele os seus discípulos, disse-lhes: Em verdade vos digo que esta pobre viúva deu mais do que todos os que deitavam ofertas no cofre;");
    b->dados[MARCOS].capitulos[12].versos[44] = wxT("porque todos deram daquilo que lhes sobrava; mas esta, da sua pobreza, deu tudo o que tinha, mesmo todo o seu sustento.");

    b->dados[MARCOS].capitulos[13].versos[1] = wxT("Quando saía do templo, disse-lhe um dos seus discípulos: Mestre, olha que pedras e que edifícios!");
    b->dados[MARCOS].capitulos[13].versos[2] = wxT("Ao que Jesus lhe disse: Vês estes grandes edifícios? Não se deixará aqui pedra sobre pedra que não seja derribada.");
    b->dados[MARCOS].capitulos[13].versos[3] = wxT("Depois estando ele sentado no Monte das Oliveiras, defronte do templo, Pedro, Tiago, João e André perguntaram-lhe em particular:");
    b->dados[MARCOS].capitulos[13].versos[4] = wxT("Dize-nos, quando sucederão essas coisas, e que sinal haverá quando todas elas estiverem para se cumprir?");
    b->dados[MARCOS].capitulos[13].versos[5] = wxT("Então Jesus começou a dizer-lhes: Acautelai-vos; ninguém vos engane;");
    b->dados[MARCOS].capitulos[13].versos[6] = wxT("muitos virão em meu nome, dizendo: Sou eu; e a muitos enganarão.");
    b->dados[MARCOS].capitulos[13].versos[7] = wxT("Quando, porém, ouvirdes falar em guerras e rumores de guerras, não vos perturbeis; forçoso é que assim aconteça: mas ainda não é o fim.");
    b->dados[MARCOS].capitulos[13].versos[8] = wxT("Pois se levantará nação contra nação, e reino contra reino; e haverá terremotos em diversos lugares, e haverá fomes. Isso será o princípio das dores.");
    b->dados[MARCOS].capitulos[13].versos[9] = wxT("Mas olhai por vós mesmos; pois por minha causa vos hão de entregar aos sinédrios e às sinagogas, e sereis açoitados; também sereis levados perante governadores e reis, para lhes servir de testemunho.");
    b->dados[MARCOS].capitulos[13].versos[10] = wxT("Mas importa que primeiro o evangelho seja pregado entre todas as nações.");
    b->dados[MARCOS].capitulos[13].versos[11] = wxT("Quando, pois, vos conduzirem para vos entregar, não vos preocupeis com o que haveis de dizer; mas, o que vos for dado naquela hora, isso falai; porque não sois vós que falais, mas sim o Espírito Santo.");
    b->dados[MARCOS].capitulos[13].versos[12] = wxT("Um irmão entregará à morte a seu irmão, e um pai a seu filho; e filhos se levantarão contra os pais e os matarão.");
    b->dados[MARCOS].capitulos[13].versos[13] = wxT("E sereis odiados de todos por causa do meu nome; mas aquele que perseverar até o fim, esse será salvo.");
    b->dados[MARCOS].capitulos[13].versos[14] = wxT("Ora, quando vós virdes a abominação da desolação estar onde não deve estar {quem lê, entenda}, então os que estiverem na Judéia fujam para os montes;");
    b->dados[MARCOS].capitulos[13].versos[15] = wxT("quem estiver no eirado não desça, nem entre para tirar alguma coisa da sua casa;");
    b->dados[MARCOS].capitulos[13].versos[16] = wxT("e quem estiver no campo não volte atrás para buscar a sua capa.");
    b->dados[MARCOS].capitulos[13].versos[17] = wxT("Mas ai das que estiverem grávidas, e das que amamentarem naqueles dias!");
    b->dados[MARCOS].capitulos[13].versos[18] = wxT("Orai, pois, para que isto não suceda no inverno;");
    b->dados[MARCOS].capitulos[13].versos[19] = wxT("porque naqueles dias haverá uma tribulação tal, qual nunca houve desde o princípio da criação, que Deus criou, até agora, nem jamais haverá.");
    b->dados[MARCOS].capitulos[13].versos[20] = wxT("Se o Senhor não abreviasse aqueles dias, ninguém se salvaria mas ele, por causa dos eleitos que escolheu, abreviou aqueles dias.");
    b->dados[MARCOS].capitulos[13].versos[21] = wxT("Então, se alguém vos disser: Eis aqui o Cristo! ou: Ei-lo ali! não acrediteis.");
    b->dados[MARCOS].capitulos[13].versos[22] = wxT("Porque hão de surgir falsos cristos e falsos profetas, e farão sinais e prodígios para enganar, se possível, até os escolhidos.");
    b->dados[MARCOS].capitulos[13].versos[23] = wxT("Ficai vós, pois, de sobreaviso; eis que de antemão vos tenho dito tudo.");
    b->dados[MARCOS].capitulos[13].versos[24] = wxT("Mas naqueles dias, depois daquela tribulação, o sol escurecerá, e a lua não dará a sua luz;");
    b->dados[MARCOS].capitulos[13].versos[25] = wxT("as estrelas cairão do céu, e os poderes que estão nos céus, serão abalados.");
    b->dados[MARCOS].capitulos[13].versos[26] = wxT("Então verão vir o Filho do homem nas nuvens, com grande poder e glória.");
    b->dados[MARCOS].capitulos[13].versos[27] = wxT("E logo enviará os seus anjos, e ajuntará os seus eleitos, desde os quatro ventos, desde a extremidade da terra até a extremidade do céu.");
    b->dados[MARCOS].capitulos[13].versos[28] = wxT("Da figueira, pois, aprendei a parábola: Quando já o seu ramo se torna tenro e brota folhas, sabeis que está próximo o verão.");
    b->dados[MARCOS].capitulos[13].versos[29] = wxT("Assim também vós, quando virdes sucederem essas coisas, sabei que ele está próximo, mesmo às portas.");
    b->dados[MARCOS].capitulos[13].versos[30] = wxT("Em verdade vos digo que não passará esta geração, até que todas essas coisas aconteçam.");
    b->dados[MARCOS].capitulos[13].versos[31] = wxT("Passará o céu e a terra, mas as minhas palavras não passarão.");
    b->dados[MARCOS].capitulos[13].versos[32] = wxT("Quanto, porém, ao dia e à hora, ninguém sabe, nem os anjos no céu nem o Filho, senão o Pai.");
    b->dados[MARCOS].capitulos[13].versos[33] = wxT("Olhai! vigiai! porque não sabeis quando chegará o tempo.");
    b->dados[MARCOS].capitulos[13].versos[34] = wxT("É como se um homem, devendo viajar, ao deixar a sua casa, desse autoridade aos seus servos, a cada um o seu trabalho, e ordenasse também ao porteiro que vigiasse.");
    b->dados[MARCOS].capitulos[13].versos[35] = wxT("Vigiai, pois; porque não sabeis quando virá o senhor da casa; se à tarde, se à meia-noite, se ao cantar do galo, se pela manhã;");
    b->dados[MARCOS].capitulos[13].versos[36] = wxT("para que, vindo de improviso, não vos ache dormindo.");
    b->dados[MARCOS].capitulos[13].versos[37] = wxT("O que vos digo a vós, a todos o digo: Vigiai.");

    b->dados[MARCOS].capitulos[14].versos[1] = wxT("Ora, dali a dois dias era a páscoa e a festa dos pães ázimos; e os principais sacerdotes e os escribas andavam buscando como prender Jesus a traição, para o matarem.");
    b->dados[MARCOS].capitulos[14].versos[2] = wxT("Pois eles diziam: Não durante a festa, para que não haja tumulto entre o povo.");
    b->dados[MARCOS].capitulos[14].versos[3] = wxT("Estando ele em Betânia, reclinado à mesa em casa de Simão, o leproso, veio uma mulher que trazia um vaso de alabastro cheio de bálsamo de nardo puro, de grande preço; e, quebrando o vaso, derramou-lhe sobre a cabeça o bálsamo.");
    b->dados[MARCOS].capitulos[14].versos[4] = wxT("Mas alguns houve que em si mesmos se indignaram e disseram: Para que se fez este desperdício do bálsamo?");
    b->dados[MARCOS].capitulos[14].versos[5] = wxT("Pois podia ser vendido por mais de trezentos denários que se dariam aos pobres. E bramavam contra ela.");
    b->dados[MARCOS].capitulos[14].versos[6] = wxT("Jesus, porém, disse: Deixai-a; por que a molestais? Ela praticou uma boa ação para comigo.");
    b->dados[MARCOS].capitulos[14].versos[7] = wxT("Porquanto os pobres sempre os tendes convosco e, quando quiserdes, podeis fazer-lhes bem; a mim, porém, nem sempre me tendes.");
    b->dados[MARCOS].capitulos[14].versos[8] = wxT("ela fez o que pode; antecipou-se a ungir o meu corpo para a sepultura.");
    b->dados[MARCOS].capitulos[14].versos[9] = wxT("Em verdade vos digo que, em todo o mundo, onde quer que for pregado o evangelho, também o que ela fez será contado para memória sua.");
    b->dados[MARCOS].capitulos[14].versos[10] = wxT("Então Judas Iscariotes, um dos doze, foi ter com os principais sacerdotes para lhes entregar Jesus.");
    b->dados[MARCOS].capitulos[14].versos[11] = wxT("Ouvindo-o eles, alegraram-se, e prometeram dar-lhe dinheiro. E buscava como o entregaria em ocasião oportuna.");
    b->dados[MARCOS].capitulos[14].versos[12] = wxT("Ora, no primeiro dia dos pães ázimos, quando imolavam a páscoa, disseram-lhe seus discípulos: Aonde queres que vamos fazer os preparativos para comeres a páscoa?");
    b->dados[MARCOS].capitulos[14].versos[13] = wxT("Enviou, pois, dois dos seus discípulos, e disse-lhes: Ide à cidade, e vos sairá ao encontro um homem levando um cântaro de água; seguí-o;");
    b->dados[MARCOS].capitulos[14].versos[14] = wxT("e, onde ele entrar, dizei ao dono da casa: O Mestre manda perguntar: Onde está o meu aposento em que hei de comer a páscoa com os meus discípulos?");
    b->dados[MARCOS].capitulos[14].versos[15] = wxT("E ele vos mostrará um grande cenáculo mobiliado e pronto; aí fazei-nos os preparativos.");
    b->dados[MARCOS].capitulos[14].versos[16] = wxT("Partindo, pois, os discípulos, foram à cidade, onde acharam tudo como ele lhes dissera, e prepararam a páscoa.");
    b->dados[MARCOS].capitulos[14].versos[17] = wxT("Ao anoitecer chegou ele com os doze.");
    b->dados[MARCOS].capitulos[14].versos[18] = wxT("E, quando estavam reclinados à mesa e comiam, disse Jesus: Em verdade vos digo que um de vós, que comigo come, há de trair-me.");
    b->dados[MARCOS].capitulos[14].versos[19] = wxT("Ao que eles começaram a entristecer-se e a perguntar-lhe um após outro: Porventura sou eu?");
    b->dados[MARCOS].capitulos[14].versos[20] = wxT("Respondeu-lhes: É um dos doze, que mete comigo a mão no prato.");
    b->dados[MARCOS].capitulos[14].versos[21] = wxT("Pois o Filho do homem vai, conforme está escrito a seu respeito; mas ai daquele por quem o Filho do homem é traído! bom seria para esse homem se não houvera nascido.");
    b->dados[MARCOS].capitulos[14].versos[22] = wxT("Enquanto comiam, Jesus tomou pão e, abençoando-o, o partiu e deu-lho, dizendo: Tomai; isto é o meu corpo.");
    b->dados[MARCOS].capitulos[14].versos[23] = wxT("E tomando um cálice, rendeu graças e deu-lho; e todos beberam dele.");
    b->dados[MARCOS].capitulos[14].versos[24] = wxT("E disse-lhes: Isto é o meu sangue, o sangue do pacto, que por muitos é derramado.");
    b->dados[MARCOS].capitulos[14].versos[25] = wxT("Em verdade vos digo que não beberei mais do fruto da videira, até aquele dia em que o beber, novo, no reino de Deus.");
    b->dados[MARCOS].capitulos[14].versos[26] = wxT("E, tendo cantado um hino, saíram para o Monte das Oliveiras.");
    b->dados[MARCOS].capitulos[14].versos[27] = wxT("Disse-lhes então Jesus: Todos vós vos escandalizareis; porque escrito está: Ferirei o pastor, e as ovelhas se dispersarão.");
    b->dados[MARCOS].capitulos[14].versos[28] = wxT("Todavia, depois que eu ressurgir, irei adiante de vós para a Galiléia.");
    b->dados[MARCOS].capitulos[14].versos[29] = wxT("Ao que Pedro lhe disse: Ainda que todos se escandalizem, nunca, porém, eu.");
    b->dados[MARCOS].capitulos[14].versos[30] = wxT("Replicou-lhe Jesus: Em verdade te digo que hoje, nesta noite, antes que o galo cante duas vezes, três vezes tu me negarás.");
    b->dados[MARCOS].capitulos[14].versos[31] = wxT("Mas ele repetia com veemência: Ainda que me seja necessário morrer contigo, de modo nenhum te negarei. Assim também diziam todos.");
    b->dados[MARCOS].capitulos[14].versos[32] = wxT("Então chegaram a um lugar chamado Getsêmani, e disse Jesus a seus discípulos: Sentai-vos aqui, enquanto eu oro.");
    b->dados[MARCOS].capitulos[14].versos[33] = wxT("E levou consigo a Pedro, a Tiago e a João, e começou a ter pavor e a angustiar-se;");
    b->dados[MARCOS].capitulos[14].versos[34] = wxT("e disse-lhes: A minha alma está triste até a morte; ficai aqui e vigiai.");
    b->dados[MARCOS].capitulos[14].versos[35] = wxT("E adiantando-se um pouco, prostrou-se em terra; e orava para que, se fosse possível, passasse dele aquela hora.");
    b->dados[MARCOS].capitulos[14].versos[36] = wxT("E dizia: Aba, Pai, tudo te é possível; afasta de mim este cálice; todavia não seja o que eu quero, mas o que tu queres.");
    b->dados[MARCOS].capitulos[14].versos[37] = wxT("Voltando, achou-os dormindo; e disse a Pedro: Simão, dormes? não pudeste vigiar uma hora?");
    b->dados[MARCOS].capitulos[14].versos[38] = wxT("Vigiai e orai, para que não entreis em tentação; o espírito, na verdade, está pronto, mas a carne é fraca.");
    b->dados[MARCOS].capitulos[14].versos[39] = wxT("Retirou-se de novo e orou, dizendo as mesmas palavras.");
    b->dados[MARCOS].capitulos[14].versos[40] = wxT("E voltando outra vez, achou-os dormindo, porque seus olhos estavam carregados; e não sabiam o que lhe responder.");
    b->dados[MARCOS].capitulos[14].versos[41] = wxT("Ao voltar pela terceira vez, disse-lhes: Dormi agora e descansai.-Basta; é chegada a hora. Eis que o Filho do homem está sendo entregue nas mãos dos pecadores.");
    b->dados[MARCOS].capitulos[14].versos[42] = wxT("Levantai-vos, vamo-nos; eis que é chegado aquele que me trai.");
    b->dados[MARCOS].capitulos[14].versos[43] = wxT("E logo, enquanto ele ainda falava, chegou Judas, um dos doze, e com ele uma multidão com espadas e varapaus, vinda da parte dos principais sacerdotes, dos escribas e dos anciãos.");
    b->dados[MARCOS].capitulos[14].versos[44] = wxT("Ora, o que o traía lhes havia dado um sinal, dizendo: Aquele que eu beijar, esse é; prendei-o e levai-o com segurança.");
    b->dados[MARCOS].capitulos[14].versos[45] = wxT("E, logo que chegou, aproximando-se de Jesus, disse: Rabi! E o beijou.");
    b->dados[MARCOS].capitulos[14].versos[46] = wxT("Ao que eles lhes lançaram as mãos, e o prenderam.");
    b->dados[MARCOS].capitulos[14].versos[47] = wxT("Mas um dos que ali estavam, puxando da espada, feriu o servo do sumo sacerdote e cortou-lhe uma orelha.");
    b->dados[MARCOS].capitulos[14].versos[48] = wxT("Disse-lhes Jesus: Saístes com espadas e varapaus para me prender, como a um salteador?");
    b->dados[MARCOS].capitulos[14].versos[49] = wxT("Todos os dias estava convosco no templo, a ensinar, e não me prendestes; mas isto é para que se cumpram as Escrituras.");
    b->dados[MARCOS].capitulos[14].versos[50] = wxT("Nisto, todos o deixaram e fugiram.");
    b->dados[MARCOS].capitulos[14].versos[51] = wxT("Ora, seguia-o certo jovem envolto em um lençol sobre o corpo nu; e o agarraram.");
    b->dados[MARCOS].capitulos[14].versos[52] = wxT("Mas ele, largando o lençol, fugiu despido.");
    b->dados[MARCOS].capitulos[14].versos[53] = wxT("Levaram Jesus ao sumo sacerdote, e ajuntaram-se todos os principais sacerdotes, os anciãos e os escribas.");
    b->dados[MARCOS].capitulos[14].versos[54] = wxT("E Pedro o seguiu de longe até dentro do pátio do sumo sacerdote, e estava sentado com os guardas, aquentando-se ao fogo.");
    b->dados[MARCOS].capitulos[14].versos[55] = wxT("Os principais sacerdotes testemunho contra Jesus para o matar, e não o achavam.");
    b->dados[MARCOS].capitulos[14].versos[56] = wxT("Porque contra ele muitos depunham falsamente, mas os testemunhos não concordavam.");
    b->dados[MARCOS].capitulos[14].versos[57] = wxT("Levantaram-se por fim alguns que depunham falsamente contra ele, dizendo:");
    b->dados[MARCOS].capitulos[14].versos[58] = wxT("Nós o ouvimos dizer: Eu destruirei este santuário, construído por mãos de homens, e em três dias edificarei outro, não feito por mãos de homens.");
    b->dados[MARCOS].capitulos[14].versos[59] = wxT("E nem assim concordava o seu testemunho.");
    b->dados[MARCOS].capitulos[14].versos[60] = wxT("Levantou-se então o sumo sacerdote no meio e perguntou a Jesus: Não respondes coisa alguma? Que é que estes depõem conta ti?");
    b->dados[MARCOS].capitulos[14].versos[61] = wxT("Ele, porém, permaneceu calado, e nada respondeu. Tornou o sumo sacerdote a interrogá-lo, perguntando-lhe: És tu o Cristo, o Filho do Deus bendito?");
    b->dados[MARCOS].capitulos[14].versos[62] = wxT("Respondeu Jesus: Eu o sou; e vereis o Filho do homem assentado à direita do Poder e vindo com as nuvens do céu.");
    b->dados[MARCOS].capitulos[14].versos[63] = wxT("Então o sumo sacerdote, rasgando as suas vestes, disse: Para que precisamos ainda de testemunhas?");
    b->dados[MARCOS].capitulos[14].versos[64] = wxT("Acabais de ouvir a blasfêmia; que vos parece? E todos o condenaram como réu de morte.");
    b->dados[MARCOS].capitulos[14].versos[65] = wxT("E alguns começaram a cuspir nele, e a cobrir-lhe o rosto, e a dar-lhe socos, e a dizer-lhe: Profetiza. E os guardas receberam-no a bofetadas.");
    b->dados[MARCOS].capitulos[14].versos[66] = wxT("Ora, estando Pedro em baixo, no átrio, chegou uma das criadas do sumo sacerdote");
    b->dados[MARCOS].capitulos[14].versos[67] = wxT("e, vendo a Pedro, que se estava aquentando, encarou-o e disse: Tu também estavas com o nazareno, esse Jesus.");
    b->dados[MARCOS].capitulos[14].versos[68] = wxT("Mas ele o negou, dizendo: Não sei nem compreendo o que dizes. E saiu para o alpendre.");
    b->dados[MARCOS].capitulos[14].versos[69] = wxT("E a criada, vendo-o, começou de novo a dizer aos que ali estavam: Esse é um deles.");
    b->dados[MARCOS].capitulos[14].versos[70] = wxT("Mas ele o negou outra vez. E pouco depois os que ali estavam disseram novamente a Pedro: Certamente tu és um deles; pois és também galileu.");
    b->dados[MARCOS].capitulos[14].versos[71] = wxT("Ele, porém, começou a praguejar e a jurar: Não conheço esse homem de quem falais.");
    b->dados[MARCOS].capitulos[14].versos[72] = wxT("Nesse instante o galo cantou pela segunda vez. E Pedro lembrou-se da palavra que lhe dissera Jesus: Antes que o galo cante duas vezes, três vezes me negarás. E caindo em si, começou a chorar.");

    b->dados[MARCOS].capitulos[15].versos[1] = wxT("Logo de manhã tiveram conselho os principais sacerdotes com os anciãos, os escribas e todo o sinédrio; e maniatando a Jesus, o levaram e o entregaram a Pilatos.");
    b->dados[MARCOS].capitulos[15].versos[2] = wxT("Pilatos lhe perguntou: És tu o rei dos judeus? Respondeu-lhe Jesus: É como dizes.");
    b->dados[MARCOS].capitulos[15].versos[3] = wxT("e os principais dos sacerdotes o acusavam de muitas coisas.");
    b->dados[MARCOS].capitulos[15].versos[4] = wxT("Tornou Pilatos a interrogá-lo, dizendo: Não respondes nada? Vê quantas acusações te fazem.");
    b->dados[MARCOS].capitulos[15].versos[5] = wxT("Mas Jesus nada mais respondeu, de maneira que Pilatos se admirava.");
    b->dados[MARCOS].capitulos[15].versos[6] = wxT("Ora, por ocasião da festa costumava soltar-lhes um preso qualquer que eles pedissem.");
    b->dados[MARCOS].capitulos[15].versos[7] = wxT("E havia um, chamado Barrabás, preso com outros sediciosos, os quais num motim haviam cometido um homicídio.");
    b->dados[MARCOS].capitulos[15].versos[8] = wxT("E a multidão subiu e começou a pedir o que lhe costumava fazer.");
    b->dados[MARCOS].capitulos[15].versos[9] = wxT("Ao que Pilatos lhes perguntou: Quereis que vos solte o rei dos judeus?");
    b->dados[MARCOS].capitulos[15].versos[10] = wxT("Pois ele sabia que por inveja os principais sacerdotes lho haviam entregado.");
    b->dados[MARCOS].capitulos[15].versos[11] = wxT("Mas os principais sacerdotes incitaram a multidão a pedir que lhes soltasse antes a Barrabás.");
    b->dados[MARCOS].capitulos[15].versos[12] = wxT("E Pilatos, tornando a falar, perguntou-lhes: Que farei então daquele a quem chamais reis dos judeus?");
    b->dados[MARCOS].capitulos[15].versos[13] = wxT("Novamente clamaram eles: Crucifica-o!");
    b->dados[MARCOS].capitulos[15].versos[14] = wxT("Disse-lhes Pilatos: Mas que mal fez ele? Ao que eles clamaram ainda mais: Crucifica-o!");
    b->dados[MARCOS].capitulos[15].versos[15] = wxT("Então Pilatos, querendo satisfazer a multidão, soltou-lhe Barrabás; e tendo mandado açoitar a Jesus, o entregou para ser crucificado.");
    b->dados[MARCOS].capitulos[15].versos[16] = wxT("Os soldados, pois, levaram-no para dentro, ao pátio, que é o pretório, e convocaram toda a corte;");
    b->dados[MARCOS].capitulos[15].versos[17] = wxT("vestiram-no de púrpura e puseram-lhe na cabeça uma coroa de espinhos que haviam tecido;");
    b->dados[MARCOS].capitulos[15].versos[18] = wxT("e começaram a saudá-lo: Salve, rei dos judeus!");
    b->dados[MARCOS].capitulos[15].versos[19] = wxT("Davam-lhe com uma cana na cabeça, cuspiam nele e, postos de joelhos, o adoravam.");
    b->dados[MARCOS].capitulos[15].versos[20] = wxT("Depois de o terem assim escarnecido, despiram-lhe a púrpura, e lhe puseram as vestes. Então o levaram para fora, a fim de o crucificarem.");
    b->dados[MARCOS].capitulos[15].versos[21] = wxT("E obrigaram certo Simão, cireneu, pai de Alexandre e de Rufo, que por ali passava, vindo do campo, a carregar-lhe a cruz.");
    b->dados[MARCOS].capitulos[15].versos[22] = wxT("Levaram-no, pois, ao lugar do Gólgota, que quer dizer, lugar da Caveira.");
    b->dados[MARCOS].capitulos[15].versos[23] = wxT("E ofereciam-lhe vinho misturado com mirra; mas ele não o tomou.");
    b->dados[MARCOS].capitulos[15].versos[24] = wxT("Então o crucificaram, e repartiram entre si as vestes dele, lançando sortes sobre elas para ver o que cada um levaria.");
    b->dados[MARCOS].capitulos[15].versos[25] = wxT("E era a hora terceira quando o crucificaram.");
    b->dados[MARCOS].capitulos[15].versos[26] = wxT("Por cima dele estava escrito o título da sua acusação: O REI DOS JUDEUS.");
    b->dados[MARCOS].capitulos[15].versos[27] = wxT("Também, com ele, crucificaram dois salteadores, um à sua direita, e outro à esquerda.");
    b->dados[MARCOS].capitulos[15].versos[28] = wxT("{E cumpriu-se a escritura que diz: E com os malfeitores foi contado.}");
    b->dados[MARCOS].capitulos[15].versos[29] = wxT("E os que iam passando blasfemavam dele, meneando a cabeça e dizendo: Ah! tu que destróis o santuário e em três dias o reedificas.");
    b->dados[MARCOS].capitulos[15].versos[30] = wxT("salva-te a ti mesmo, descendo da cruz.");
    b->dados[MARCOS].capitulos[15].versos[31] = wxT("De igual modo também os principais sacerdotes, com os escribas, escarnecendo-o, diziam entre si: A outros salvou; a si mesmo não pode salvar;");
    b->dados[MARCOS].capitulos[15].versos[32] = wxT("desça agora da cruz o Cristo, o rei de Israel, para que vejamos e creiamos, Também os que com ele foram crucificados o injuriavam.");
    b->dados[MARCOS].capitulos[15].versos[33] = wxT("E, chegada a hora sexta, houve trevas sobre a terra, até a hora nona.");
    b->dados[MARCOS].capitulos[15].versos[34] = wxT("E, à hora nona, bradou Jesus em alta voz: Eloí, Eloí, lamá, sabactani? que, traduzido, é: Deus meu, Deus meu, por que me desamparaste?");
    b->dados[MARCOS].capitulos[15].versos[35] = wxT("Alguns dos que ali estavam, ouvindo isso, diziam: Eis que chama por Elias.");
    b->dados[MARCOS].capitulos[15].versos[36] = wxT("Correu um deles, ensopou uma esponja em vinagre e, pondo-a numa cana, dava-lhe de beber, dizendo: Deixai, vejamos se Elias virá tirá-lo.");
    b->dados[MARCOS].capitulos[15].versos[37] = wxT("Mas Jesus, dando um grande brado, expirou.");
    b->dados[MARCOS].capitulos[15].versos[38] = wxT("Então o véu do santuário se rasgou em dois, de alto a baixo.");
    b->dados[MARCOS].capitulos[15].versos[39] = wxT("Ora, o centurião, que estava defronte dele, vendo-o assim expirar, disse: Verdadeiramente este homem era filho de Deus.");
    b->dados[MARCOS].capitulos[15].versos[40] = wxT("Também ali estavam algumas mulheres olhando de longe, entre elas Maria Madalena, Maria, mãe de Tiago o Menor e de José, e Salomé;");
    b->dados[MARCOS].capitulos[15].versos[41] = wxT("as quais o seguiam e o serviam quando ele estava na Galiléia; e muitas outras que tinham subido com ele a Jerusalém.");
    b->dados[MARCOS].capitulos[15].versos[42] = wxT("Ao cair da tarde, como era o dia da preparação, isto é, a véspera do sábado,");
    b->dados[MARCOS].capitulos[15].versos[43] = wxT("José de Arimatéia, ilustre membro do sinédrio, que também esperava o reino de Deus, cobrando ânimo foi Pilatos e pediu o corpo de Jesus.");
    b->dados[MARCOS].capitulos[15].versos[44] = wxT("Admirou-se Pilatos de que já tivesse morrido; e chamando o centurião, perguntou-lhe se, de fato, havia morrido.");
    b->dados[MARCOS].capitulos[15].versos[45] = wxT("E, depois que o soube do centurião, cedeu o cadáver a José;");
    b->dados[MARCOS].capitulos[15].versos[46] = wxT("o qual, tendo comprado um pano de linho, tirou da cruz o corpo, envolveu-o no pano e o depositou num sepulcro aberto em rocha; e rolou uma pedra para a porta do sepulcro.");
    b->dados[MARCOS].capitulos[15].versos[47] = wxT("E Maria Madalena e Maria, mãe de José, observavam onde fora posto.");

    b->dados[MARCOS].capitulos[16].versos[1] = wxT("Ora, passado o sábado, Maria Madalena, Maria, mãe de Tiago, e Salomé, compraram aromas para irem ungi-lo.");
    b->dados[MARCOS].capitulos[16].versos[2] = wxT("E, no primeiro dia da semana, foram ao sepulcro muito cedo, ao levantar do sol.");
    b->dados[MARCOS].capitulos[16].versos[3] = wxT("E diziam umas às outras: Quem nos revolverá a pedra da porta do sepulcro?");
    b->dados[MARCOS].capitulos[16].versos[4] = wxT("Mas, levantando os olhos, notaram que a pedra, que era muito grande, já estava revolvida;");
    b->dados[MARCOS].capitulos[16].versos[5] = wxT("e entrando no sepulcro, viram um moço sentado à direita, vestido de alvo manto; e ficaram atemorizadas.");
    b->dados[MARCOS].capitulos[16].versos[6] = wxT("Ele, porém, lhes disse: Não vos atemorizeis; buscais a Jesus, o nazareno, que foi crucificado; ele ressurgiu; não está aqui; eis o lugar onde o puseram.");
    b->dados[MARCOS].capitulos[16].versos[7] = wxT("Mas ide, dizei a seus discípulos, e a Pedro, que ele vai adiante de vós para a Galiléia; ali o vereis, como ele vos disse.");
    b->dados[MARCOS].capitulos[16].versos[8] = wxT("E, saindo elas, fugiram do sepulcro, porque estavam possuídas de medo e assombro; e não disseram nada a ninguém, porque temiam.");
    b->dados[MARCOS].capitulos[16].versos[9] = wxT("Ora, havendo Jesus ressurgido cedo no primeiro dia da semana, apareceu primeiramente a Maria Madalena, da qual tinha expulsado sete demônios.");
    b->dados[MARCOS].capitulos[16].versos[10] = wxT("Foi ela anunciá-lo aos que haviam andado com ele, os quais estavam tristes e chorando;");
    b->dados[MARCOS].capitulos[16].versos[11] = wxT("e ouvindo eles que vivia, e que tinha sido visto por ela, não o creram.");
    b->dados[MARCOS].capitulos[16].versos[12] = wxT("Depois disso manifestou-se sob outra forma a dois deles que iam de caminho para o campo,");
    b->dados[MARCOS].capitulos[16].versos[13] = wxT("os quais foram anunciá-lo aos outros; mas nem a estes deram crédito.");
    b->dados[MARCOS].capitulos[16].versos[14] = wxT("Por último, então, apareceu aos onze, estando eles reclinados à mesa, e lançou-lhes em rosto a sua incredulidade e dureza de coração, por não haverem dado crédito aos que o tinham visto já ressurgido.");
    b->dados[MARCOS].capitulos[16].versos[15] = wxT("E disse-lhes: Ide por todo o mundo, e pregai o evangelho a toda criatura.");
    b->dados[MARCOS].capitulos[16].versos[16] = wxT("Quem crer e for batizado será salvo; mas quem não crer será condenado.");
    b->dados[MARCOS].capitulos[16].versos[17] = wxT("E estes sinais acompanharão aos que crerem: em meu nome expulsarão demônios; falarão novas línguas;");
    b->dados[MARCOS].capitulos[16].versos[18] = wxT("pegarão em serpentes; e se beberem alguma coisa mortífera, não lhes fará dano algum; e porão as mãos sobre os enfermos, e estes serão curados.");
    b->dados[MARCOS].capitulos[16].versos[19] = wxT("Ora, o Senhor, depois de lhes ter falado, foi recebido no céu, e assentou-se à direita de Deus.");
    b->dados[MARCOS].capitulos[16].versos[20] = wxT("Eles, pois, saindo, pregaram por toda parte, cooperando com eles o Senhor, e confirmando a palavra com os sinais que os acompanhavam.");

}
